using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Reflection;
using Newtonsoft.Json;
using UnityEngine;

namespace UnityGameTranslator.Core
{
    /// <summary>
    /// Loads custom SDF fonts from JSON + PNG files generated by msdf-atlas-gen.
    /// Allows users to add support for non-Latin scripts (CJK, Devanagari, Arabic, etc.)
    /// by placing font files in the plugin's fonts/ folder.
    /// </summary>
    public static class CustomFontLoader
    {
        #region JSON Schema (msdf-atlas-gen format)

        [Serializable]
        public class MsdfAtlasData
        {
            public AtlasInfo atlas { get; set; }
            public MetricsInfo metrics { get; set; }
            public List<GlyphInfo> glyphs { get; set; }
            public List<KerningInfo> kerning { get; set; }
        }

        [Serializable]
        public class AtlasInfo
        {
            public string type { get; set; }
            public float distanceRange { get; set; }
            public float size { get; set; }
            public int width { get; set; }
            public int height { get; set; }
            public string yOrigin { get; set; } // "bottom" or "top"
        }

        [Serializable]
        public class MetricsInfo
        {
            public float emSize { get; set; }
            public float lineHeight { get; set; }
            public float ascender { get; set; }
            public float descender { get; set; }
            public float underlineY { get; set; }
            public float underlineThickness { get; set; }
        }

        [Serializable]
        public class GlyphInfo
        {
            public int unicode { get; set; }
            public float advance { get; set; }
            public BoundsInfo planeBounds { get; set; }
            public BoundsInfo atlasBounds { get; set; }
        }

        [Serializable]
        public class BoundsInfo
        {
            public float left { get; set; }
            public float bottom { get; set; }
            public float right { get; set; }
            public float top { get; set; }
        }

        [Serializable]
        public class KerningInfo
        {
            public int unicode1 { get; set; }
            public int unicode2 { get; set; }
            public float advance { get; set; }
        }

        #endregion

        #region Custom Font Info

        /// <summary>
        /// Information about a loaded custom font.
        /// </summary>
        public class CustomFontInfo
        {
            public string Name { get; set; }
            public string JsonPath { get; set; }
            public string PngPath { get; set; }
            public MsdfAtlasData AtlasData { get; set; }
            public Texture2D AtlasTexture { get; set; }
            public object FontAsset { get; set; } // TMP_FontAsset or TMProOld.TMP_FontAsset
            public bool IsLoaded { get; set; }
            public string Error { get; set; }

            // For TTF fonts: path to the .ttf/.otf file (rasterized on demand)
            public string TtfPath { get; set; }
            public bool IsTtf => !string.IsNullOrEmpty(TtfPath);

            // For TTF-rasterized fonts: RGBA pixels stored in memory (no PNG file)
            public byte[] RgbaPixels { get; set; }
            public int RgbaWidth { get; set; }
            public int RgbaHeight { get; set; }

            // Source: "custom" (fonts/ folder), "system" (OS fonts)
            public string Source { get; set; }
        }

        #endregion

        // Loaded custom fonts (from fonts/ folder only)
        private static readonly Dictionary<string, CustomFontInfo> _customFonts = new Dictionary<string, CustomFontInfo>();

        // Cache folder path (mod's fonts/ directory) for system font rasterization cache
        private static string _cacheFolderPath;

        // Cached type references for reflection
        private static Type _tmpFontAssetType;
        private static Type _tmpGlyphType;
        private static Type _tmpTextElementType;
        private static Type _faceInfoType;
        private static bool _typesInitialized;
        private static bool _useAlternateTMP;
        private static bool _existingFontDumped;

        /// <summary>
        /// Gets all available custom fonts (loaded or not).
        /// </summary>
        public static IReadOnlyDictionary<string, CustomFontInfo> CustomFonts => _customFonts;

        /// <summary>
        /// Scans the fonts folder and loads all available custom fonts.
        /// </summary>
        public static void Initialize(string pluginFolder)
        {
            var fontsFolder = Path.Combine(pluginFolder, "fonts");
            _cacheFolderPath = fontsFolder;
            int loadedCount = 0;

            if (!Directory.Exists(fontsFolder))
            {
                TranslatorCore.LogInfo($"[CustomFontLoader] No fonts folder found at {fontsFolder}");
                return;
            }

            TranslatorCore.LogInfo($"[CustomFontLoader] Scanning fonts folder: {fontsFolder}");

            // Find all JSON files (skip .cache.json — those are TTF rasterization cache)
            var jsonFiles = Directory.GetFiles(fontsFolder, "*.json");

            foreach (var jsonPath in jsonFiles)
            {
                var fileName = Path.GetFileNameWithoutExtension(jsonPath);

                // Skip generated cache files (from TTF rasterizer)
                if (fileName.EndsWith(".cache") || fileName.EndsWith(".gen"))
                    continue;

                var pngPath = Path.Combine(fontsFolder, fileName + ".png");

                if (!File.Exists(pngPath))
                {
                    TranslatorCore.LogWarning($"[CustomFontLoader] Missing PNG for {fileName}.json");
                    continue;
                }

                var fontInfo = new CustomFontInfo
                {
                    Name = fileName,
                    JsonPath = jsonPath,
                    PngPath = pngPath
                };

                try
                {
                    var jsonContent = File.ReadAllText(jsonPath);
                    fontInfo.AtlasData = JsonConvert.DeserializeObject<MsdfAtlasData>(jsonContent);

                    if (fontInfo.AtlasData?.glyphs == null || fontInfo.AtlasData.glyphs.Count == 0)
                    {
                        fontInfo.Error = "No glyphs in JSON";
                        TranslatorCore.LogWarning($"[CustomFontLoader] {fileName}: No glyphs found in JSON");
                    }
                    else
                    {
                        TranslatorCore.LogInfo($"[CustomFontLoader] Found {fileName}: {fontInfo.AtlasData.glyphs.Count} glyphs, {fontInfo.AtlasData.atlas.width}x{fontInfo.AtlasData.atlas.height} atlas");
                        loadedCount++;
                    }
                }
                catch (Exception ex)
                {
                    fontInfo.Error = $"JSON parse error: {ex.Message}";
                    TranslatorCore.LogWarning($"[CustomFontLoader] Failed to parse {fileName}.json: {ex.Message}");
                }

                _customFonts[fileName] = fontInfo;
            }

            // Scan for TTF/OTF files — register only, rasterize on demand
            foreach (var ext in new[] { "*.ttf", "*.otf" })
            {
                string[] fontFiles;
                try { fontFiles = Directory.GetFiles(fontsFolder, ext); }
                catch { continue; }

                foreach (var fontPath in fontFiles)
                {
                    var fileName = Path.GetFileNameWithoutExtension(fontPath);
                    if (_customFonts.ContainsKey(fileName))
                        continue;

                    _customFonts[fileName] = new CustomFontInfo
                    {
                        Name = fileName,
                        TtfPath = fontPath,
                        Source = "custom"
                    };
                    loadedCount++;
                    TranslatorCore.LogInfo($"[CustomFontLoader] Registered TTF: {fileName} (will rasterize on demand)");
                }
            }

            TranslatorCore.LogInfo($"[CustomFontLoader] Found {loadedCount} custom font(s)");
        }

        /// <summary>
        /// Gets the names of all available custom fonts (from fonts/ folder only).
        /// </summary>
        public static string[] GetCustomFontNames()
        {
            var names = new List<string>();
            foreach (var kvp in _customFonts)
            {
                if (string.IsNullOrEmpty(kvp.Value.Error))
                    names.Add(kvp.Key);
            }
            return names.ToArray();
        }

        /// <summary>
        /// Try to find a .ttf/.otf file for a system font name on the filesystem.
        /// Handles display names like "Adobe Devanagari Italic" → "AdobeDevanagari-Italic.otf"
        /// by normalizing names (stripping spaces, checking with style suffixes).
        /// </summary>
        public static string FindSystemTtfPath(string fontName)
        {
            if (string.IsNullOrEmpty(fontName)) return null;

            var dirs = new List<string>();
            try
            {
                var winFonts = Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.Windows), "Fonts");
                if (Directory.Exists(winFonts)) dirs.Add(winFonts);
                var userFonts = Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData),
                    "Microsoft", "Windows", "Fonts");
                if (Directory.Exists(userFonts)) dirs.Add(userFonts);
                if (Directory.Exists("/usr/share/fonts")) dirs.Add("/usr/share/fonts");
                if (Directory.Exists("/Library/Fonts")) dirs.Add("/Library/Fonts");
            }
            catch { }

            // Build candidate filenames from the display name
            // "Adobe Devanagari Italic" → try: "Adobe Devanagari Italic", "AdobeDevanagari-Italic",
            //   "AdobeDevanagariItalic", "AdobeDevanagari-Italic", etc.
            var candidates = BuildFilenameCandidates(fontName);

            foreach (var dir in dirs)
            {
                // 1. Try exact candidates
                foreach (var candidate in candidates)
                {
                    foreach (var ext in new[] { ".ttf", ".otf" })
                    {
                        var path = Path.Combine(dir, candidate + ext);
                        if (File.Exists(path)) return path;
                    }
                }

                // 2. Fuzzy match: scan all font files and compare normalized names
                try
                {
                    string normalizedSearch = NormalizeFontName(fontName);
                    foreach (var ext in new[] { "*.ttf", "*.otf" })
                    {
                        foreach (var file in Directory.GetFiles(dir, ext, SearchOption.AllDirectories))
                        {
                            string fileName = Path.GetFileNameWithoutExtension(file);
                            if (string.Equals(NormalizeFontName(fileName), normalizedSearch,
                                StringComparison.OrdinalIgnoreCase))
                                return file;
                        }
                    }
                }
                catch { }
            }

            return null;
        }

        /// <summary>
        /// Build candidate filenames from a font display name.
        /// </summary>
        private static string[] BuildFilenameCandidates(string displayName)
        {
            var candidates = new List<string>();
            candidates.Add(displayName); // exact

            // Split into name + style parts
            // "Adobe Devanagari Bold Italic" → family="Adobe Devanagari", style="Bold Italic"
            string[] styleSuffixes = { "Bold Italic", "Bold", "Italic", "Regular", "Light", "Medium",
                "SemiBold", "ExtraBold", "Thin", "Black", "Condensed" };

            string family = displayName;
            string style = "";
            foreach (var suffix in styleSuffixes)
            {
                if (displayName.EndsWith(" " + suffix, StringComparison.OrdinalIgnoreCase))
                {
                    family = displayName.Substring(0, displayName.Length - suffix.Length - 1);
                    style = suffix;
                    break;
                }
            }

            string familyNoSpaces = family.Replace(" ", "");
            string styleNoSpaces = style.Replace(" ", "");

            // "AdobeDevanagari-Italic"
            if (!string.IsNullOrEmpty(style))
            {
                candidates.Add(familyNoSpaces + "-" + styleNoSpaces);
                candidates.Add(familyNoSpaces + style);
                candidates.Add(familyNoSpaces + "-" + style);
            }
            // "AdobeDevanagari-Regular" (when no style suffix detected)
            candidates.Add(familyNoSpaces + "-Regular");
            candidates.Add(familyNoSpaces);
            candidates.Add(displayName.Replace(" ", ""));

            return candidates.ToArray();
        }

        /// <summary>
        /// Normalize a font name for fuzzy comparison: lowercase, strip spaces/hyphens/underscores.
        /// "Adobe Devanagari Italic" and "AdobeDevanagari-Italic" both become "adobedevanagariitalic".
        /// </summary>
        private static string NormalizeFontName(string name)
        {
            if (string.IsNullOrEmpty(name)) return "";
            var sb = new System.Text.StringBuilder(name.Length);
            for (int i = 0; i < name.Length; i++)
            {
                char c = name[i];
                if (c != ' ' && c != '-' && c != '_')
                    sb.Append(char.ToLowerInvariant(c));
            }
            return sb.ToString();
        }

        /// <summary>
        /// Rasterize a system font by name. Called as fallback when CreateDynamicFontFromOSFont fails.
        /// Uses FontManager.GetSystemFontPath for proper name→path resolution.
        /// Returns a TMP_FontAsset or null.
        /// </summary>
        public static object LoadSystemTtfFont(string fontName)
        {
            // Check if already rasterized (cached in _customFonts)
            CustomFontInfo fontInfo;
            if (_customFonts.TryGetValue(fontName, out fontInfo) && fontInfo.IsLoaded && fontInfo.FontAsset != null)
                return fontInfo.FontAsset;

            // Find the .ttf file path — FontManager has the name→path mapping
            var ttfPath = FontManager.GetSystemFontPath(fontName);
            if (ttfPath == null)
            {
                TranslatorCore.LogWarning($"[CustomFontLoader] System TTF not found: {fontName}");
                return null;
            }

            TranslatorCore.LogInfo($"[CustomFontLoader] Resolved system font '{fontName}' -> {ttfPath}");

            // Register as custom font with TTF path, then load via existing pipeline
            if (!_customFonts.ContainsKey(fontName))
            {
                _customFonts[fontName] = new CustomFontInfo
                {
                    Name = fontName,
                    TtfPath = ttfPath,
                    Source = "system"
                };
            }

            return LoadCustomFont(fontName);
        }

        // Cache of Unity Fonts created from TTF rasterization (for UI.Text replacement)
        // Stored as object to avoid Font type reference that crashes IL2CPP JIT
        private static readonly Dictionary<string, object> _rasterizedUnityFonts = new Dictionary<string, object>(StringComparer.OrdinalIgnoreCase);

        /// <summary>
        /// Create a Unity Font (for UI.Text) from a TTF file by rasterizing glyphs to a bitmap atlas.
        /// This is the fallback for IL2CPP where CreateDynamicFontFromOSFont is stripped.
        /// ALL Font/CharacterInfo access is via reflection to avoid IL2CPP JIT crashes.
        /// </summary>
        public static Font CreateUnityFontFromTtf(string fontName)
        {
            object cached;
            if (_rasterizedUnityFonts.TryGetValue(fontName, out cached) && cached is Font cachedFont)
                return cachedFont;

            var result = CreateUnityFontFromTtfReflection(fontName);
            return result as Font;
        }

        /// <summary>
        /// Internal: creates Font entirely via reflection. No direct Font/CharacterInfo references
        /// to prevent IL2CPP JIT resolution crashes on stripped methods.
        /// </summary>
        private static object CreateUnityFontFromTtfReflection(string fontName)
        {
            // Find TTF path
            string ttfPath = null;
            CustomFontInfo fontInfo;
            if (_customFonts.TryGetValue(fontName, out fontInfo) && fontInfo.IsTtf)
                ttfPath = fontInfo.TtfPath;
            if (ttfPath == null)
                ttfPath = FontManager.GetSystemFontPath(fontName);
            if (ttfPath == null)
                ttfPath = FindSystemTtfPath(fontName);

            if (ttfPath == null)
            {
                TranslatorCore.LogWarning($"[CustomFontLoader] Cannot find TTF for Unity font: {fontName}");
                return null;
            }

            try
            {
                TranslatorCore.LogInfo($"[CustomFontLoader] Creating Unity Font from TTF: {fontName} -> {ttfPath}");

                var fontData = System.IO.File.ReadAllBytes(ttfPath);
                var parser = new Rasterizer.TtfParser(fontData);
                var codepoints = parser.GetSupportedCodepoints();
                var metrics = parser.Metrics;
                float upm = metrics.UnitsPerEm;
                float renderSize = 48f;
                int padding = 1;

                // Rasterize
                var rasterizedGlyphs = new List<Rasterizer.RasterizedGlyph>();
                var outlines = new List<Rasterizer.GlyphOutline>();
                for (int i = 0; i < codepoints.Length && i < Rasterizer.TtfFontPipeline.MaxGlyphCount; i++)
                {
                    var outline = parser.GetGlyphOutline(codepoints[i]);
                    if (outline == null) continue;
                    var rasterized = Rasterizer.GlyphRasterizer.Rasterize(outline, metrics, renderSize, padding);
                    if (rasterized == null) continue;
                    rasterized.Unicode = codepoints[i];
                    rasterizedGlyphs.Add(rasterized);
                    outlines.Add(outline);
                }

                // Pack atlas
                var packable = new List<Rasterizer.RasterizedGlyph>();
                foreach (var rg in rasterizedGlyphs)
                    if (rg.Bitmap != null && rg.Width > 0 && rg.Height > 0) packable.Add(rg);
                packable.Sort((a, b) => b.Height.CompareTo(a.Height));
                var atlasResult = Rasterizer.AtlasPacker.PackAtlas(packable);
                int atlasW = atlasResult.Width, atlasH = atlasResult.Height;

                // Atlas from packer has R=G=B=bitmap, A=255 (grayscale)
                // GUI/Text Shader reads alpha for glyph mask → copy R to A, set RGB=255
                var rgba = atlasResult.RgbaData;
                for (int pi = 0; pi < atlasW * atlasH; pi++)
                {
                    int idx = pi * 4;
                    byte val = rgba[idx]; // bitmap value from R channel
                    rgba[idx] = val;       // R = bitmap (some shaders read R)
                    rgba[idx + 1] = val;   // G = bitmap
                    rgba[idx + 2] = val;   // B = bitmap
                    rgba[idx + 3] = val;   // A = bitmap (GUI/Text Shader reads A)
                }

                // Save as real PNG then reload via LoadImage — same proven path as TMP fonts.
                // This is the only reliable cross-runtime method (Mono + IL2CPP).
                string cacheDir = _cacheFolderPath;
                if (string.IsNullOrEmpty(cacheDir))
                {
                    // No fonts folder configured — try to find one
                    CustomFontInfo fi;
                    if (_customFonts.TryGetValue(fontName, out fi) && fi.TtfPath != null)
                        cacheDir = Path.GetDirectoryName(fi.TtfPath);
                }

                Texture2D texture = null;

                if (!string.IsNullOrEmpty(cacheDir))
                {
                    if (!Directory.Exists(cacheDir))
                        Directory.CreateDirectory(cacheDir);

                    string pngPath = Path.Combine(cacheDir, fontName + ".uitext.png");

                    // Create temp texture with SetPixels32Safe, encode to PNG, reload via LoadImage
                    var tmpTex = new Texture2D(atlasW, atlasH, TextureFormat.RGBA32, false);
                    var colors = new Color32[atlasW * atlasH];
                    for (int row = 0; row < atlasH; row++)
                    {
                        int srcRow = atlasH - 1 - row; // Flip for SetPixels32
                        for (int col = 0; col < atlasW; col++)
                        {
                            int srcIdx = (srcRow * atlasW + col) * 4;
                            colors[row * atlasW + col] = new Color32(rgba[srcIdx], rgba[srcIdx + 1], rgba[srcIdx + 2], rgba[srcIdx + 3]);
                        }
                    }
                    SetPixels32Safe(tmpTex, colors);
                    tmpTex.Apply();

                    byte[] pngData = EncodeToPngSafe(tmpTex);
                    UnityEngine.Object.Destroy(tmpTex);

                    if (pngData != null && pngData.Length > 0)
                    {
                        File.WriteAllBytes(pngPath, pngData);
                        TranslatorCore.LogInfo($"[CustomFontLoader] Saved Unity Font atlas PNG: {pngPath} ({pngData.Length} bytes)");

                        // Reload via LoadImage — the proven path
                        texture = new Texture2D(2, 2, TextureFormat.RGBA32, false);
                        texture.filterMode = FilterMode.Bilinear;
                        if (!LoadImageToTexture(texture, pngData))
                        {
                            TranslatorCore.LogWarning("[CustomFontLoader] LoadImage failed for Unity Font atlas");
                            texture = null;
                        }
                    }
                    else
                    {
                        TranslatorCore.LogWarning("[CustomFontLoader] EncodeToPNG failed for Unity Font atlas");
                    }
                }

                if (texture == null)
                {
                    TranslatorCore.LogWarning("[CustomFontLoader] Failed to create Unity Font atlas texture");
                    return null;
                }

                TranslatorCore.LogInfo($"[CustomFontLoader] Unity Font texture loaded: {texture.width}x{texture.height}");

                // Create Font via reflection only
                var fontType = typeof(Font);
                object font = null;

                // Try Font(string) constructor
                try
                {
                    var ctor = fontType.GetConstructor(new Type[] { typeof(string) });
                    if (ctor != null) font = ctor.Invoke(new object[] { fontName });
                }
                catch { }

                // Try Font() parameterless
                if (font == null)
                {
                    try
                    {
                        var ctor = fontType.GetConstructor(Type.EmptyTypes);
                        if (ctor != null) font = ctor.Invoke(null);
                    }
                    catch { }
                }

                if (font == null)
                {
                    TranslatorCore.LogWarning("[CustomFontLoader] Cannot create Font instance on this runtime");
                    return null;
                }

                // Set name
                if (font is UnityEngine.Object uobj) uobj.name = fontName;

                // Set material — try to copy from an existing game font for correct shader
                Material mat = null;
                try
                {
                    var gameFonts = TypeHelper.FindAllObjectsOfType(typeof(Font));
                    foreach (var gf in gameFonts)
                    {
                        if (gf == null || gf == font) continue;
                        var gfMat = GetPropertyOrField(gf, typeof(Font), "material") as Material;
                        if (gfMat != null && gfMat.shader != null)
                        {
                            mat = new Material(gfMat.shader);
                            mat.CopyPropertiesFromMaterial(gfMat);
                            TranslatorCore.LogInfo($"[CustomFontLoader] Copied material from game font: {gf.name}, shader: {gfMat.shader.name}");
                            break;
                        }
                    }
                }
                catch { }

                if (mat == null)
                {
                    var shader = Shader.Find("UI/Default") ?? Shader.Find("Sprites/Default") ?? Shader.Find("GUI/Text Shader");
                    if (shader != null) mat = new Material(shader);
                }

                if (mat != null)
                {
                    mat.mainTexture = texture;
                    mat.name = fontName + " Material";
                    SetPropertyOrField(font, fontType, "material", mat);
                    TranslatorCore.LogInfo($"[CustomFontLoader] Font material set, shader: {mat.shader?.name}, tex: {texture.width}x{texture.height}");
                }

                // Build CharacterInfo array and assign to Font.
                // On IL2CPP, Font.characterInfo property accepts a managed CharacterInfo[]
                // and converts internally. The key is that CharacterInfo struct fields must be
                // set BEFORE the struct is placed in the array (value type semantics).
                float scale = renderSize / upm;
                int ciCount = 0;
                for (int i = 0; i < rasterizedGlyphs.Count; i++)
                    if (i < outlines.Count && outlines[i] != null) ciCount++;

                // Build managed CharacterInfo[] with all values set at construction
                var ciArray = new CharacterInfo[ciCount];
                int ciWriteIdx = 0;

                for (int i = 0; i < rasterizedGlyphs.Count; i++)
                {
                    var rg = rasterizedGlyphs[i];
                    var outline = i < outlines.Count ? outlines[i] : null;
                    if (outline == null) continue;

                    // Build the struct completely before writing to array
                    CharacterInfo ci = default;

                    // Use reflection to set each property on the boxed struct,
                    // then unbox back before array assignment
                    object boxed = (object)ci;

                    SetPropertyOrField(boxed, typeof(CharacterInfo), "index", rg.Unicode);
                    SetPropertyOrField(boxed, typeof(CharacterInfo), "advance", (int)(rg.AdvanceWidth * scale + 0.5f));

                    if (rg.Bitmap != null && rg.Width > 0 && rg.Height > 0)
                    {
                        float uvLeft = (float)rg.AtlasX / atlasW;
                        float uvRight = (float)(rg.AtlasX + rg.Width) / atlasW;
                        float uvTop = 1f - (float)rg.AtlasY / atlasH;
                        float uvBottom = 1f - (float)(rg.AtlasY + rg.Height) / atlasH;

                        SetPropertyOrField(boxed, typeof(CharacterInfo), "uvBottomLeft", new Vector2(uvLeft, uvBottom));
                        SetPropertyOrField(boxed, typeof(CharacterInfo), "uvBottomRight", new Vector2(uvRight, uvBottom));
                        SetPropertyOrField(boxed, typeof(CharacterInfo), "uvTopLeft", new Vector2(uvLeft, uvTop));
                        SetPropertyOrField(boxed, typeof(CharacterInfo), "uvTopRight", new Vector2(uvRight, uvTop));
                        SetPropertyOrField(boxed, typeof(CharacterInfo), "minX", (int)(outline.XMin * scale - padding));
                        SetPropertyOrField(boxed, typeof(CharacterInfo), "maxX", (int)(outline.XMax * scale + padding));
                        SetPropertyOrField(boxed, typeof(CharacterInfo), "minY", (int)(outline.YMin * scale - padding));
                        SetPropertyOrField(boxed, typeof(CharacterInfo), "maxY", (int)(outline.YMax * scale + padding));
                        SetPropertyOrField(boxed, typeof(CharacterInfo), "glyphWidth", rg.Width);
                        SetPropertyOrField(boxed, typeof(CharacterInfo), "glyphHeight", rg.Height);
                    }

                    // Unbox back to struct and assign to array
                    ciArray[ciWriteIdx] = (CharacterInfo)boxed;
                    ciWriteIdx++;
                }

                // Assign to Font — the property setter handles managed→IL2CPP conversion
                var ciPropForType = fontType.GetProperty("characterInfo", BindingFlags.Public | BindingFlags.Instance);
                bool ciSet = false;
                if (ciPropForType != null)
                {
                    try
                    {
                        ciPropForType.SetValue(font, ciArray, null);
                        ciSet = true;
                    }
                    catch (Exception ex)
                    {
                        TranslatorCore.LogWarning($"[CustomFontLoader] characterInfo property set failed: {ex.Message}");
                    }
                }
                if (!ciSet)
                    ciSet = SetPropertyOrField(font, fontType, "characterInfo", ciArray);

                TranslatorCore.LogInfo($"[CustomFontLoader] characterInfo set={ciSet}, length={ciWriteIdx}");

                // If characterInfo assignment failed, this font is unusable — return null
                // so the caller can fall back to UI.Text → TMP conversion
                if (!ciSet)
                {
                    TranslatorCore.LogWarning("[CustomFontLoader] CharacterInfo not supported on this runtime — font unusable");
                    if (font is UnityEngine.Object fontToDestroy)
                        UnityEngine.Object.Destroy(fontToDestroy);
                    return null;
                }

                // Verify: read back characterInfo and inspect first element
                var readBack = GetPropertyOrField(font, fontType, "characterInfo");
                if (readBack != null)
                {
                    var rbType = readBack.GetType();
                    var countProp = rbType.GetProperty("Length") ?? rbType.GetProperty("Count");
                    int rbCount = countProp != null ? (int)countProp.GetValue(readBack, null) : -1;
                    TranslatorCore.LogInfo($"[CustomFontLoader] characterInfo readback: type={rbType.Name}, count={rbCount}");

                    // Dump first element to verify values were written
                    if (rbCount > 0)
                    {
                        try
                        {
                            var indexer = rbType.GetProperty("Item");
                            if (indexer != null)
                            {
                                var firstCi = indexer.GetValue(readBack, new object[] { 0 });
                                if (firstCi != null)
                                {
                                    var t = firstCi.GetType();
                                    var props = t.GetProperties(BindingFlags.Public | BindingFlags.Instance);
                                    var vals = new List<string>();
                                    foreach (var p in props)
                                    {
                                        try { vals.Add($"{p.Name}={p.GetValue(firstCi, null)}"); }
                                        catch { vals.Add($"{p.Name}=err"); }
                                    }
                                    TranslatorCore.LogInfo($"[CustomFontLoader] CI[0]: {string.Join(", ", vals)}");
                                }
                            }
                        }
                        catch (Exception ex)
                        {
                            TranslatorCore.LogWarning($"[CustomFontLoader] CI dump failed: {ex.Message}");
                        }
                    }
                }
                else
                {
                    TranslatorCore.LogWarning("[CustomFontLoader] characterInfo readback is NULL");
                }

                // Also verify material
                var readMat = GetPropertyOrField(font, fontType, "material");
                TranslatorCore.LogInfo($"[CustomFontLoader] material readback: {(readMat != null ? "OK" : "NULL")}, " +
                    $"texture={(readMat is Material m ? (m.mainTexture != null ? $"{m.mainTexture.width}x{m.mainTexture.height}" : "null") : "?")}");

                TranslatorCore.LogInfo($"[CustomFontLoader] Created Unity Font '{fontName}': {ciWriteIdx} characters, {atlasW}x{atlasH} atlas");

                _rasterizedUnityFonts[fontName] = font;
                return font;
            }
            catch (Exception ex)
            {
                TranslatorCore.LogError($"[CustomFontLoader] Failed to create Unity Font from TTF: {ex}");
                return null;
            }
        }

        /// <summary>
        /// Loads a custom font's texture and creates the TMP_FontAsset.
        /// Call this lazily when the font is actually needed.
        /// </summary>
        public static object LoadCustomFont(string fontName)
        {
            CustomFontInfo fontInfo;
            if (!_customFonts.TryGetValue(fontName, out fontInfo))
            {
                TranslatorCore.LogWarning($"[CustomFontLoader] Font not found: {fontName}");
                return null;
            }

            if (fontInfo.IsLoaded && fontInfo.FontAsset != null)
                return fontInfo.FontAsset;

            if (!string.IsNullOrEmpty(fontInfo.Error))
            {
                TranslatorCore.LogWarning($"[CustomFontLoader] Cannot load {fontName}: {fontInfo.Error}");
                return null;
            }

            // TTF font not yet rasterized — do it now (on demand)
            if (fontInfo.IsTtf && fontInfo.AtlasData == null && fontInfo.RgbaPixels == null)
            {
                TranslatorCore.LogInfo($"[CustomFontLoader] Rasterizing TTF on demand: {fontName}");
                try
                {
                    // Cache always goes in the mod's fonts/ folder
                    string cacheDir = fontInfo.Source == "system" ? _cacheFolderPath : null;
                    var cached = Rasterizer.TtfFontPipeline.TryLoadCache(fontInfo.TtfPath, cacheDir);
                    if (cached == null)
                    {
                        cached = Rasterizer.TtfFontPipeline.ProcessTtfFont(fontInfo.TtfPath);
                        if (cached != null)
                        {
                            // Ensure cache dir exists for system fonts
                            if (cacheDir != null && !Directory.Exists(cacheDir))
                                Directory.CreateDirectory(cacheDir);
                            Rasterizer.TtfFontPipeline.SaveCache(fontInfo.TtfPath, cached, cacheDir);
                        }
                    }

                    if (cached != null && cached.AtlasData?.glyphs != null && cached.AtlasData.glyphs.Count > 0)
                    {
                        fontInfo.AtlasData = cached.AtlasData;
                        fontInfo.RgbaPixels = cached.RgbaPixels;
                        fontInfo.RgbaWidth = cached.Width;
                        fontInfo.RgbaHeight = cached.Height;
                        TranslatorCore.LogInfo($"[CustomFontLoader] TTF rasterized: {fontName} " +
                            $"({cached.AtlasData.glyphs.Count} glyphs, {cached.Width}x{cached.Height})");
                    }
                    else
                    {
                        fontInfo.Error = "TTF rasterization failed";
                        TranslatorCore.LogWarning($"[CustomFontLoader] TTF rasterization failed: {fontName}");
                        return null;
                    }
                }
                catch (Exception ex)
                {
                    fontInfo.Error = $"TTF error: {ex.Message}";
                    TranslatorCore.LogError($"[CustomFontLoader] TTF error for {fontName}: {ex}");
                    return null;
                }
            }

            try
            {
                Texture2D texture;

                if (fontInfo.RgbaPixels != null && fontInfo.RgbaWidth > 0 && fontInfo.RgbaHeight > 0)
                {
                    // TTF-rasterized font: create texture, save as real PNG for cache,
                    // then reload via the same LoadImage path as JSON+PNG fonts
                    int w = fontInfo.RgbaWidth;
                    int h = fontInfo.RgbaHeight;
                    var rgba = fontInfo.RgbaPixels;

                    // Create temporary texture to encode as PNG
                    // Flip: our RGBA is top-to-bottom, SetPixels32 expects bottom-to-top
                    var tmpTex = new Texture2D(w, h, TextureFormat.RGBA32, false);
                    var colors = new Color32[w * h];
                    for (int row = 0; row < h; row++)
                    {
                        int srcRow = h - 1 - row;
                        for (int col = 0; col < w; col++)
                        {
                            int srcIdx = (srcRow * w + col) * 4;
                            colors[row * w + col] = new Color32(rgba[srcIdx], rgba[srcIdx + 1], rgba[srcIdx + 2], rgba[srcIdx + 3]);
                        }
                    }
                    SetPixels32Safe(tmpTex, colors);
                    tmpTex.Apply();

                    // Save as real PNG via EncodeToPNG (reflection for IL2CPP compatibility)
                    string cacheDir = fontInfo.Source == "system" ? _cacheFolderPath : Path.GetDirectoryName(fontInfo.TtfPath ?? "");
                    if (!string.IsNullOrEmpty(cacheDir))
                    {
                        if (!Directory.Exists(cacheDir))
                            Directory.CreateDirectory(cacheDir);

                        // Use .gen.png/.gen.json to distinguish from user-provided fonts
                        string pngPath = Path.Combine(cacheDir, fontName + ".gen.png");
                        string jsonPath = Path.Combine(cacheDir, fontName + ".gen.json");

                        try
                        {
                            byte[] pngData = EncodeToPngSafe(tmpTex);
                            if (pngData != null && pngData.Length > 0)
                            {
                                File.WriteAllBytes(pngPath, pngData);
                                var json = Newtonsoft.Json.JsonConvert.SerializeObject(fontInfo.AtlasData, Newtonsoft.Json.Formatting.None);
                                File.WriteAllText(jsonPath, json);

                                // Switch to the JSON+PNG path: set PngPath and clear RGBA
                                fontInfo.PngPath = pngPath;
                                fontInfo.RgbaPixels = null;

                                TranslatorCore.LogInfo($"[CustomFontLoader] Saved TTF atlas as PNG: {pngPath} ({pngData.Length} bytes)");
                            }
                            else
                            {
                                TranslatorCore.LogWarning("[CustomFontLoader] EncodeToPNG returned null/empty");
                            }
                        }
                        catch (Exception ex)
                        {
                            TranslatorCore.LogWarning($"[CustomFontLoader] Failed to save PNG cache: {ex.Message}");
                        }
                    }

                    UnityEngine.Object.Destroy(tmpTex);
                    fontInfo.RgbaPixels = null;

                    // Now load via the standard PNG path (same as JSON+PNG custom fonts)
                    if (!string.IsNullOrEmpty(fontInfo.PngPath) && File.Exists(fontInfo.PngPath))
                    {
                        var pngBytes = File.ReadAllBytes(fontInfo.PngPath);
                        texture = new Texture2D(2, 2, TextureFormat.RGBA32, false);
                        texture.filterMode = FilterMode.Bilinear;

                        if (!LoadImageToTexture(texture, pngBytes))
                        {
                            fontInfo.Error = "Failed to load cached PNG";
                            TranslatorCore.LogWarning($"[CustomFontLoader] Failed to load cached PNG for {fontName}");
                            return null;
                        }

                        // SDF is in alpha channel (R=G=B=255, A=SDF) — check if conversion needed
                        ConvertSdfTextureForTMP(texture);
                        TranslatorCore.LogInfo($"[CustomFontLoader] Loaded TTF atlas from PNG: {texture.width}x{texture.height}");
                    }
                    else
                    {
                        fontInfo.Error = "PNG cache not available";
                        TranslatorCore.LogWarning($"[CustomFontLoader] No PNG cache for {fontName}");
                        return null;
                    }
                }
                else
                {
                    // JSON+PNG font: load from file
                    var pngData = File.ReadAllBytes(fontInfo.PngPath);
                    texture = new Texture2D(2, 2, TextureFormat.RGBA32, false);
                    texture.filterMode = FilterMode.Bilinear;

                    if (!LoadImageToTexture(texture, pngData))
                    {
                        fontInfo.Error = "Failed to load PNG";
                        TranslatorCore.LogWarning($"[CustomFontLoader] Failed to load PNG for {fontName}");
                        return null;
                    }

                    // For SDF fonts, the distance field is in RGB (grayscale) but TMP expects it in Alpha
                    // Convert by copying R channel to Alpha
                    ConvertSdfTextureForTMP(texture);
                }

                fontInfo.AtlasTexture = texture;
                TranslatorCore.LogInfo($"[CustomFontLoader] Loaded texture: {texture.width}x{texture.height}, format: {texture.format}");

                // Debug: Check if texture has actual content (not all white/transparent)
                try
                {
                    byte[] rawSample = GetRawTextureDataSafe(texture);
                    int bpp = GetBytesPerPixel(texture.format);
                    int pixelCount = rawSample.Length / bpp;
                    int sampleSize = Math.Min(100, pixelCount);
                    int nonWhiteCount = 0;
                    for (int pi = 0; pi < sampleSize; pi++)
                    {
                        int idx = pi * bpp;
                        if (idx + bpp > rawSample.Length) break;
                        bool isWhite = true;
                        for (int b = 0; b < bpp && b < 4; b++)
                        {
                            if (rawSample[idx + b] < 252) { isWhite = false; break; }
                        }
                        if (!isWhite) nonWhiteCount++;
                    }
                    TranslatorCore.LogInfo($"[CustomFontLoader] Texture sample: {nonWhiteCount}/{sampleSize} non-white pixels");
                }
                catch (Exception ex)
                {
                    TranslatorCore.LogWarning($"[CustomFontLoader] Could not sample texture: {ex.Message}");
                }

                // Initialize type references if needed
                if (!_typesInitialized)
                    InitializeTypes();

                // Create the font asset
                fontInfo.FontAsset = CreateFontAsset(fontInfo);
                fontInfo.IsLoaded = true;

                if (fontInfo.FontAsset != null)
                {
                    TranslatorCore.LogInfo($"[CustomFontLoader] Successfully created font asset for {fontName}");
                }
                else
                {
                    fontInfo.Error = "Failed to create font asset";
                }

                return fontInfo.FontAsset;
            }
            catch (Exception ex)
            {
                fontInfo.Error = $"Load error: {ex.Message}";
                TranslatorCore.LogError($"[CustomFontLoader] Error loading {fontName}: {ex}");
                return null;
            }
        }

        /// <summary>
        /// Initializes type references for TMP classes via reflection.
        /// </summary>
        /// <summary>
        /// FindObjectsOfTypeAll compatible with IL2CPP.
        /// On IL2CPP, Resources.FindObjectsOfTypeAll(Type) may have different signature.
        /// </summary>
        private static UnityEngine.Object[] FindObjectsOfTypeAllSafe(Type type)
        {
            if (type == null) return new UnityEngine.Object[0];

            // Try direct call
            try
            {
                return Resources.FindObjectsOfTypeAll(type);
            }
            catch { }

            // IL2CPP: try via reflection on the actual Resources type
            try
            {
                var resourcesType = typeof(Resources);
                foreach (var method in resourcesType.GetMethods(BindingFlags.Public | BindingFlags.Static))
                {
                    if (method.Name != "FindObjectsOfTypeAll") continue;
                    var parameters = method.GetParameters();
                    if (parameters.Length != 1) continue;

                    // Accept any single-parameter overload
                    try
                    {
                        object arg = type;
                        // If the parameter expects an IL2CPP Type, we may need to convert
                        var paramType = parameters[0].ParameterType;
                        if (paramType == typeof(Type) || paramType.IsAssignableFrom(typeof(Type)))
                        {
                            var result = method.Invoke(null, new object[] { type });
                            if (result is UnityEngine.Object[] array) return array;

                            // IL2CPP may return Il2CppReferenceArray
                            if (result != null)
                            {
                                var list = new List<UnityEngine.Object>();
                                if (result is System.Collections.IEnumerable enumerable)
                                {
                                    foreach (var item in enumerable)
                                    {
                                        if (item is UnityEngine.Object uobj)
                                            list.Add(uobj);
                                    }
                                }
                                if (list.Count > 0) return list.ToArray();
                            }
                        }
                    }
                    catch { continue; }
                }
            }
            catch { }

            return new UnityEngine.Object[0];
        }

        /// <summary>
        /// ScriptableObject.CreateInstance compatible with IL2CPP.
        /// On IL2CPP, the Type parameter may need to be an IL2CPP Type wrapper.
        /// </summary>
        private static UnityEngine.Object CreateScriptableObjectSafe(Type type)
        {
            // Try direct call first
            try
            {
                return ScriptableObject.CreateInstance(type);
            }
            catch { }

            // IL2CPP: try via reflection
            try
            {
                var soType = typeof(ScriptableObject);
                foreach (var method in soType.GetMethods(BindingFlags.Public | BindingFlags.Static))
                {
                    if (method.Name != "CreateInstance") continue;
                    if (method.IsGenericMethod) continue;
                    var parameters = method.GetParameters();
                    if (parameters.Length != 1) continue;

                    try
                    {
                        var result = method.Invoke(null, new object[] { type });
                        if (result is UnityEngine.Object uobj)
                            return uobj;
                    }
                    catch { continue; }
                }

                // Try generic version: ScriptableObject.CreateInstance<T>()
                var genericMethod = soType.GetMethod("CreateInstance", BindingFlags.Public | BindingFlags.Static, null, Type.EmptyTypes, null);
                if (genericMethod != null && genericMethod.IsGenericMethodDefinition)
                {
                    var specific = genericMethod.MakeGenericMethod(type);
                    var result = specific.Invoke(null, null);
                    if (result is UnityEngine.Object uobj)
                        return uobj;
                }
            }
            catch (Exception ex)
            {
                TranslatorCore.LogWarning($"[CustomFontLoader] CreateInstance reflection failed: {ex.Message}");
            }

            // Last resort: try Activator.CreateInstance
            try
            {
                var obj = Activator.CreateInstance(type);
                if (obj is UnityEngine.Object uobj)
                    return uobj;
            }
            catch { }

            TranslatorCore.LogWarning($"[CustomFontLoader] Cannot create ScriptableObject of type {type.Name}");
            return null;
        }

        /// <summary>
        /// Set a value on an object by property name first (IL2CPP), then field name (Mono).
        /// Returns true if successfully set.
        /// </summary>
        private static bool SetPropertyOrField(object obj, Type type, string name, object value)
        {
            // Try property first (IL2CPP exposes fields as properties)
            try
            {
                var prop = type.GetProperty(name, BindingFlags.Public | BindingFlags.Instance);
                if (prop != null && prop.CanWrite)
                {
                    prop.SetValue(obj, value, null);
                    return true;
                }
            }
            catch { }

            // Try field
            try
            {
                var field = type.GetField(name, BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance);
                if (field != null)
                {
                    field.SetValue(obj, value);
                    return true;
                }
            }
            catch { }

            // Try with m_ prefix (Unity convention)
            try
            {
                var field = type.GetField("m_" + name, BindingFlags.NonPublic | BindingFlags.Instance);
                if (field != null)
                {
                    field.SetValue(obj, value);
                    return true;
                }
            }
            catch { }

            return false;
        }

        /// <summary>
        /// Get a value from an object by property name first (IL2CPP), then field name (Mono).
        /// Returns null if not found.
        /// </summary>
        private static object GetPropertyOrField(object obj, Type type, string name)
        {
            try
            {
                var prop = type.GetProperty(name, BindingFlags.Public | BindingFlags.Instance);
                if (prop != null && prop.CanRead)
                    return prop.GetValue(obj, null);
            }
            catch { }

            try
            {
                var field = type.GetField(name, BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance);
                if (field != null)
                    return field.GetValue(obj);
            }
            catch { }

            try
            {
                var field = type.GetField("m_" + name, BindingFlags.NonPublic | BindingFlags.Instance);
                if (field != null)
                    return field.GetValue(obj);
            }
            catch { }

            return null;
        }

        /// <summary>
        /// Find a type by simple name in an assembly (handles IL2CPP prefixed namespaces).
        /// </summary>
        private static Type FindTypeByName(System.Reflection.Assembly asm, string typeName)
        {
            try
            {
                foreach (var type in asm.GetTypes())
                {
                    if (type.Name == typeName)
                        return type;
                }
            }
            catch { }
            return null;
        }

        private static void InitializeTypes()
        {
            _typesInitialized = true;

            // Use TypeHelper's already-resolved TMP_FontAsset type (handles IL2CPP namespaces like Il2CppTMPro)
            if (TypeHelper.TMP_FontAssetType != null)
            {
                _tmpFontAssetType = TypeHelper.TMP_FontAssetType;
                _useAlternateTMP = TypeHelper.UseAlternateTMP;

                // Find related types in the same assembly
                var asm = _tmpFontAssetType.Assembly;
                string ns = _tmpFontAssetType.Namespace ?? "";

                // Try exact namespace first, then scan by name
                _tmpGlyphType = asm.GetType(ns + ".TMP_Glyph") ?? FindTypeByName(asm, "TMP_Glyph");
                _tmpTextElementType = asm.GetType(ns + ".TMP_TextElement") ?? FindTypeByName(asm, "TMP_TextElement");
                _faceInfoType = asm.GetType(ns + ".FaceInfo") ?? FindTypeByName(asm, "FaceInfo");

                // FaceInfo may be in another assembly or have a different name on IL2CPP
                if (_faceInfoType == null)
                {
                    // Try FaceInfo_Legacy in the TMP assembly (IL2CPP games with older TMP)
                    _faceInfoType = asm.GetType(ns + ".FaceInfo_Legacy") ?? FindTypeByName(asm, "FaceInfo_Legacy");

                    // Try UnityEngine.TextCoreModule (modern TMP versions)
                    if (_faceInfoType == null)
                    {
                        foreach (var otherAsm in AppDomain.CurrentDomain.GetAssemblies())
                        {
                            if (otherAsm.GetName().Name.Contains("TextCore"))
                            {
                                _faceInfoType = otherAsm.GetType("UnityEngine.TextCore.FaceInfo")
                                    ?? otherAsm.GetType("UnityEngine.TextCore.LowLevel.FaceInfo")
                                    ?? FindTypeByName(otherAsm, "FaceInfo");
                                if (_faceInfoType != null) break;
                            }
                        }
                    }

                    if (_faceInfoType != null)
                        TranslatorCore.LogInfo($"[CustomFontLoader] Found FaceInfo: {_faceInfoType.FullName}");
                }

                TranslatorCore.LogInfo($"[CustomFontLoader] Using TypeHelper-resolved types from {asm.GetName().Name} (ns={ns})");
                TranslatorCore.LogInfo($"[CustomFontLoader] FontAsset={_tmpFontAssetType.Name}, Glyph={_tmpGlyphType?.Name ?? "null"}, FaceInfo={_faceInfoType?.Name ?? "null"}");
            }
            else
            {
                // Fallback: manual scan (pre-TypeHelper or if TypeHelper failed)
                foreach (var asm in AppDomain.CurrentDomain.GetAssemblies())
                {
                    var oldFontAsset = asm.GetType("TMProOld.TMP_FontAsset");
                    if (oldFontAsset != null)
                    {
                        _tmpFontAssetType = oldFontAsset;
                        _tmpGlyphType = asm.GetType("TMProOld.TMP_Glyph");
                        _tmpTextElementType = asm.GetType("TMProOld.TMP_TextElement");
                        _faceInfoType = asm.GetType("TMProOld.FaceInfo");
                        _useAlternateTMP = true;
                        TranslatorCore.LogInfo("[CustomFontLoader] Using TMProOld types (fallback)");
                        return;
                    }

                    var stdFontAsset = asm.GetType("TMPro.TMP_FontAsset");
                    if (stdFontAsset != null && _tmpFontAssetType == null)
                    {
                        _tmpFontAssetType = stdFontAsset;
                        _tmpGlyphType = asm.GetType("TMPro.TMP_Glyph");
                        _tmpTextElementType = asm.GetType("TMPro.TMP_TextElement");
                        _faceInfoType = asm.GetType("TMPro.FaceInfo");
                        _useAlternateTMP = false;
                    }
                }
            }

            if (_tmpFontAssetType != null)
            {
                TranslatorCore.LogInfo($"[CustomFontLoader] Using {(_useAlternateTMP ? "TMProOld" : _tmpFontAssetType.Namespace)} types");
            }
            else
            {
                TranslatorCore.LogWarning("[CustomFontLoader] No TMP types found!");
            }
        }

        /// <summary>
        /// Creates a TMP_FontAsset from the loaded custom font data.
        /// </summary>
        private static object CreateFontAsset(CustomFontInfo fontInfo)
        {
            if (_tmpFontAssetType == null)
            {
                TranslatorCore.LogWarning("[CustomFontLoader] TMP_FontAsset type not found");
                return null;
            }

            try
            {
                // Try to clone an existing font asset first (better initialization)
                object fontAsset = null;
                UnityEngine.Object sourceFont = null;
                var existingFonts = TypeHelper.FindAllObjectsOfType(_tmpFontAssetType);
                foreach (var existingFont in existingFonts)
                {
                    if (existingFont != null && existingFont.name != "NotoSansDevanagari" && existingFont.name != "KrutiDev714Normal")
                    {
                        sourceFont = existingFont;

                        // Dump the SOURCE font structure (not the clone) to see IL2CPP properties
                        DumpExistingFontStructure(existingFont);

                        // Clone using Instantiate — returns the same IL2CPP type
                        var cloned = UnityEngine.Object.Instantiate(existingFont);

                        // On IL2CPP, cast to the proper type so reflection sees all properties
                        fontAsset = TypeHelper.Il2CppCast(cloned, _tmpFontAssetType);
                        if (fontAsset is UnityEngine.Object uobj)
                            uobj.name = fontInfo.Name;

                        TranslatorCore.LogInfo($"[CustomFontLoader] Cloned existing font: {existingFont.name}, clone type: {fontAsset?.GetType().FullName}");

                        // Dump the clone to see if it has the right type
                        if (fontAsset is UnityEngine.Object clonedObj)
                            DumpExistingFontStructure(clonedObj);

                        break;
                    }
                }

                // Fallback to creating new instance if no font to clone
                if (fontAsset == null)
                {
                    fontAsset = TypeHelper.CreateScriptableObject(_tmpFontAssetType);
                    if (fontAsset is UnityEngine.Object uobj)
                        uobj.name = fontInfo.Name;
                    TranslatorCore.LogInfo("[CustomFontLoader] Created new font asset instance");
                }

                var atlas = fontInfo.AtlasData.atlas;
                var metrics = fontInfo.AtlasData.metrics;
                var pointSize = atlas.size;

                // Set atlas texture on all relevant properties
                var fontAssetType = fontAsset.GetType();
                int atlasW = fontInfo.AtlasTexture.width;
                int atlasH = fontInfo.AtlasTexture.height;

                // Set main atlas property
                SetPropertyOrField(fontAsset, fontAssetType, "atlasTexture", fontInfo.AtlasTexture);
                SetPropertyOrField(fontAsset, fontAssetType, "m_AtlasTexture", fontInfo.AtlasTexture);
                SetPropertyOrField(fontAsset, fontAssetType, "atlas", fontInfo.AtlasTexture);

                // Set atlas dimensions
                SetPropertyOrField(fontAsset, fontAssetType, "m_AtlasWidth", atlasW);
                SetPropertyOrField(fontAsset, fontAssetType, "m_AtlasHeight", atlasH);
                SetPropertyOrField(fontAsset, fontAssetType, "atlasWidth", atlasW);
                SetPropertyOrField(fontAsset, fontAssetType, "atlasHeight", atlasH);

                // Update m_AtlasTextures array element [0]
                try
                {
                    var atlasTexturesProp = fontAssetType.GetProperty("m_AtlasTextures", BindingFlags.Public | BindingFlags.Instance)
                        ?? fontAssetType.GetProperty("atlasTextures", BindingFlags.Public | BindingFlags.Instance);
                    if (atlasTexturesProp != null)
                    {
                        var atlasArray = atlasTexturesProp.GetValue(fontAsset, null);
                        if (atlasArray != null)
                        {
                            var indexer = atlasArray.GetType().GetProperty("Item");
                            if (indexer != null && indexer.CanWrite)
                            {
                                indexer.SetValue(atlasArray, fontInfo.AtlasTexture, new object[] { 0 });
                                TranslatorCore.LogInfo($"[CustomFontLoader] Set atlasTextures[0] = {atlasW}x{atlasH}");
                            }
                        }
                    }
                }
                catch (Exception ex)
                {
                    TranslatorCore.LogWarning($"[CustomFontLoader] Failed to set atlasTextures[0]: {ex.Message}");
                }

                // Set material (required for rendering)
                SetupMaterial(fontAsset, fontInfo.AtlasTexture, fontInfo.AtlasData.atlas.distanceRange);

                // Set face info / font info — use existing clone's faceInfo and modify it
                SetupFaceInfo(fontAsset, fontInfo, pointSize);

                // Set glyphs
                SetupGlyphs(fontAsset, fontInfo, pointSize);

                return fontAsset;
            }
            catch (Exception ex)
            {
                TranslatorCore.LogError($"[CustomFontLoader] Failed to create font asset: {ex}");
                return null;
            }
        }

        /// <summary>
        /// Dumps the structure of an existing font for debugging.
        /// </summary>
        private static void DumpExistingFontStructure(UnityEngine.Object existingFont)
        {
            try
            {
                TranslatorCore.LogInfo($"[CustomFontLoader] === Dumping font structure: {existingFont.name} ===");

                var type = existingFont.GetType();
                TranslatorCore.LogInfo($"[CustomFontLoader] Type: {type.FullName}");

                // List all fields
                var allFields = type.GetFields(BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance);
                TranslatorCore.LogInfo($"[CustomFontLoader] Fields ({allFields.Length}): {string.Join(", ", allFields.Select(f => f.Name))}");

                // List ALL properties — this is what IL2CPP exposes instead of fields
                var allProps = type.GetProperties(BindingFlags.Public | BindingFlags.Instance);
                var propNames = new List<string>();
                foreach (var prop in allProps)
                {
                    string info = prop.Name;
                    try
                    {
                        var val = prop.GetValue(existingFont, null);
                        if (val != null)
                        {
                            var valType = val.GetType();
                            if (val is string s)
                                info += $"=\"{(s.Length > 30 ? s.Substring(0, 30) + "..." : s)}\"";
                            else if (val is int || val is float || val is bool)
                                info += $"={val}";
                            else
                                info += $":{valType.Name}";
                        }
                        else
                        {
                            info += "=null";
                        }
                    }
                    catch
                    {
                        info += "=(error)";
                    }
                    propNames.Add(info);
                }
                TranslatorCore.LogInfo($"[CustomFontLoader] Properties ({allProps.Length}): {string.Join(", ", propNames)}");

                // Dump properties related to glyphs, characters, atlas, material
                foreach (var prop in allProps)
                {
                    string lowerName = prop.Name.ToLower();
                    if (lowerName.Contains("glyph") || lowerName.Contains("character") ||
                        lowerName.Contains("atlas") || lowerName.Contains("material") ||
                        lowerName.Contains("face") || lowerName.Contains("font"))
                    {
                        try
                        {
                            var value = prop.GetValue(existingFont, null);
                            if (value != null)
                            {
                                var valType = value.GetType();
                                // Check for collection types
                                var countProp = valType.GetProperty("Count");
                                if (countProp != null)
                                {
                                    int count = (int)countProp.GetValue(value, null);
                                    TranslatorCore.LogInfo($"[CustomFontLoader] PROP {prop.Name}: {valType.Name} Count={count}");

                                    // Dump first item structure
                                    if (count > 0)
                                    {
                                        var indexer = valType.GetProperty("Item");
                                        if (indexer != null)
                                        {
                                            var firstItem = indexer.GetValue(value, new object[] { 0 });
                                            if (firstItem != null)
                                            {
                                                var itemProps = firstItem.GetType().GetProperties(BindingFlags.Public | BindingFlags.Instance);
                                                var itemInfo = new List<string>();
                                                foreach (var ip in itemProps)
                                                {
                                                    try
                                                    {
                                                        var iv = ip.GetValue(firstItem, null);
                                                        itemInfo.Add($"{ip.Name}={iv}");
                                                    }
                                                    catch { itemInfo.Add($"{ip.Name}=(err)"); }
                                                }
                                                TranslatorCore.LogInfo($"[CustomFontLoader]   [0] props: {string.Join(", ", itemInfo)}");
                                            }
                                        }
                                    }
                                }
                                else
                                {
                                    TranslatorCore.LogInfo($"[CustomFontLoader] PROP {prop.Name}: {valType.Name} = {value}");
                                }
                            }
                        }
                        catch { }
                    }
                }

                // Check for atlas field
                var atlasField = type.GetField("atlas", BindingFlags.Public | BindingFlags.Instance);
                if (atlasField != null)
                {
                    var atlas = atlasField.GetValue(existingFont) as Texture2D;
                    TranslatorCore.LogInfo($"[CustomFontLoader] atlas: {(atlas != null ? $"{atlas.width}x{atlas.height}" : "NULL")}");
                }

                // Check m_fontInfo
                var fontInfoField = type.GetField("m_fontInfo", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance);
                if (fontInfoField != null)
                {
                    var fontInfo = fontInfoField.GetValue(existingFont);
                    if (fontInfo != null)
                    {
                        var fiType = fontInfo.GetType();
                        var fiFields = fiType.GetFields(BindingFlags.Public | BindingFlags.Instance);
                        var fiValues = fiFields.Select(f => $"{f.Name}={f.GetValue(fontInfo)}");
                        TranslatorCore.LogInfo($"[CustomFontLoader] m_fontInfo: {string.Join(", ", fiValues)}");
                    }
                }

                TranslatorCore.LogInfo("[CustomFontLoader] === End dump ===");
                _existingFontDumped = true;
            }
            catch (Exception ex)
            {
                TranslatorCore.LogWarning($"[CustomFontLoader] Failed to dump font structure: {ex.Message}");
            }
        }

        /// <summary>
        /// Sets up the material for the font asset by copying from an existing game font.
        /// </summary>
        private static void SetupMaterial(object fontAsset, Texture2D atlas, float distanceRange)
        {
            try
            {
                Material material = null;

                // First, try to find an existing TMP font and copy its material/shader
                if (_tmpFontAssetType != null)
                {
                    var existingFonts = TypeHelper.FindAllObjectsOfType(_tmpFontAssetType);

                    // Debug: dump structure of first existing font (not our custom ones)
                    if (!_existingFontDumped)
                    {
                        foreach (var font in existingFonts)
                        {
                            if (font != null && font.name != "NotoSansDevanagari" && font.name != "KrutiDev714Normal")
                            {
                                DumpExistingFontStructure(font);
                                break;
                            }
                        }
                    }

                    foreach (var existingFont in existingFonts)
                    {
                        if (existingFont == null) continue;

                        // Get material from existing font
                        var matField = _tmpFontAssetType.GetField("material", BindingFlags.Public | BindingFlags.Instance);
                        var matProp = _tmpFontAssetType.GetProperty("material", BindingFlags.Public | BindingFlags.Instance);

                        Material existingMat = null;
                        if (matField != null)
                            existingMat = matField.GetValue(existingFont) as Material;
                        else if (matProp != null)
                            existingMat = matProp.GetValue(existingFont) as Material;

                        if (existingMat != null && existingMat.shader != null)
                        {
                            // Copy the material with our atlas texture
                            material = new Material(existingMat.shader);
                            material.CopyPropertiesFromMaterial(existingMat);
                            material.name = $"{((ScriptableObject)fontAsset).name} Material";
                            material.SetTexture("_MainTex", atlas);

                            // Update texture dimensions for our atlas
                            material.SetFloat("_TextureWidth", atlas.width);
                            material.SetFloat("_TextureHeight", atlas.height);

                            // GradientScale should match the SDF distanceRange from msdf-atlas-gen
                            // This controls the edge softness of the rendered text
                            material.SetFloat("_GradientScale", distanceRange);

                            TranslatorCore.LogInfo($"[CustomFontLoader] Copied material from existing font, shader: {existingMat.shader.name}");
                            TranslatorCore.LogInfo($"[CustomFontLoader] Set _TextureWidth={atlas.width}, _TextureHeight={atlas.height}, _GradientScale={distanceRange}");
                            break;
                        }
                    }
                }

                // Fallback: try to find shader directly
                if (material == null)
                {
                    string[] shaderNames = {
                        "TextMeshPro/Distance Field",
                        "TMPro/Distance Field",
                        "TextMeshPro/Mobile/Distance Field",
                        "TMPro/Mobile/Distance Field"
                    };

                    Shader shader = null;
                    foreach (var name in shaderNames)
                    {
                        shader = Shader.Find(name);
                        if (shader != null)
                        {
                            TranslatorCore.LogInfo($"[CustomFontLoader] Found shader: {name}");
                            break;
                        }
                    }

                    if (shader != null)
                    {
                        material = new Material(shader);
                        material.name = $"{((ScriptableObject)fontAsset).name} Material";
                        material.SetTexture("_MainTex", atlas);
                        material.SetFloat("_TextureWidth", atlas.width);
                        material.SetFloat("_TextureHeight", atlas.height);
                        material.SetFloat("_GradientScale", distanceRange);
                    }
                    else
                    {
                        TranslatorCore.LogWarning("[CustomFontLoader] No TMP shader found!");
                        return;
                    }
                }

                // Set material on font asset
                var materialField = _tmpFontAssetType.GetField("material", BindingFlags.Public | BindingFlags.Instance);
                if (materialField != null)
                {
                    materialField.SetValue(fontAsset, material);
                }
                else
                {
                    var materialProp = _tmpFontAssetType.GetProperty("material", BindingFlags.Public | BindingFlags.Instance);
                    if (materialProp != null && materialProp.CanWrite)
                    {
                        materialProp.SetValue(fontAsset, material);
                    }
                }

                // Debug: verify texture is set on material
                var mainTex = material.GetTexture("_MainTex");
                TranslatorCore.LogInfo($"[CustomFontLoader] Material _MainTex: {(mainTex != null ? $"{mainTex.width}x{mainTex.height}" : "NULL")}");
            }
            catch (Exception ex)
            {
                TranslatorCore.LogWarning($"[CustomFontLoader] Failed to setup material: {ex.Message}");
            }
        }

        /// <summary>
        /// Sets up the face info (font metrics).
        /// </summary>
        private static void SetupFaceInfo(object fontAsset, CustomFontInfo fontInfo, float pointSize)
        {
            var metrics = fontInfo.AtlasData.metrics;
            var atlas = fontInfo.AtlasData.atlas;

            try
            {
                // Find m_fontInfo — property on IL2CPP, field on Mono
                var fontAssetType = fontAsset.GetType();
                var fontInfoProp = fontAssetType.GetProperty("m_fontInfo", BindingFlags.Public | BindingFlags.Instance);
                var fontInfoField = fontInfoProp == null
                    ? fontAssetType.GetField("m_fontInfo", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance)
                    : null;

                if (fontInfoProp == null && fontInfoField == null)
                {
                    fontInfoProp = fontAssetType.GetProperty("fontInfo", BindingFlags.Public | BindingFlags.Instance);
                    if (fontInfoProp == null)
                    {
                        TranslatorCore.LogWarning("[CustomFontLoader] m_fontInfo not found as property or field");
                        return;
                    }
                }

                object faceInfo;

                // Try to get existing FaceInfo from clone (IL2CPP: proper typed object)
                object existingFaceInfo = fontInfoProp != null
                    ? fontInfoProp.GetValue(fontAsset, null)
                    : fontInfoField?.GetValue(fontAsset);

                if (existingFaceInfo != null)
                {
                    // Reuse existing FaceInfo and modify its values
                    faceInfo = existingFaceInfo;
                    TranslatorCore.LogInfo($"[CustomFontLoader] Reusing existing FaceInfo type: {faceInfo.GetType().Name}");
                }
                else
                {
                    // Determine the actual type expected by the fontAsset's m_fontInfo field/property
                    Type actualFaceInfoType = null;
                    if (fontInfoProp != null)
                        actualFaceInfoType = fontInfoProp.PropertyType;
                    else if (fontInfoField != null)
                        actualFaceInfoType = fontInfoField.FieldType;

                    // Try to create the correct type (FaceInfo_Legacy on IL2CPP, FaceInfo on Mono)
                    if (actualFaceInfoType != null)
                    {
                        try
                        {
                            faceInfo = Activator.CreateInstance(actualFaceInfoType);
                            TranslatorCore.LogInfo($"[CustomFontLoader] Created FaceInfo from field type: {actualFaceInfoType.FullName}");
                        }
                        catch
                        {
                            faceInfo = null;
                        }
                    }
                    else if (_faceInfoType != null)
                    {
                        try
                        {
                            faceInfo = Activator.CreateInstance(_faceInfoType);
                        }
                        catch
                        {
                            faceInfo = null;
                        }
                    }
                    else
                    {
                        faceInfo = null;
                    }

                    if (faceInfo == null)
                    {
                        TranslatorCore.LogWarning("[CustomFontLoader] FaceInfo type not found or cannot be instantiated");
                        return;
                    }
                }

                // Set fields using reflection (names may vary between TMP versions)
                float ascender = metrics.ascender * pointSize;
                float descender = metrics.descender * pointSize;
                float capHeight = ascender * 0.8f; // Approximate cap height

                SetFieldValue(faceInfo, "Name", fontInfo.Name);
                SetFieldValue(faceInfo, "PointSize", pointSize);
                SetFieldValue(faceInfo, "Scale", 1f);
                SetFieldValue(faceInfo, "CharacterCount", fontInfo.AtlasData.glyphs.Count);
                SetFieldValue(faceInfo, "LineHeight", metrics.lineHeight * pointSize);
                SetFieldValue(faceInfo, "Baseline", 0f); // Baseline is reference point, typically 0
                SetFieldValue(faceInfo, "Ascender", ascender);
                SetFieldValue(faceInfo, "CapHeight", capHeight);
                SetFieldValue(faceInfo, "Descender", descender);
                SetFieldValue(faceInfo, "CenterLine", (ascender + descender) / 2f);
                SetFieldValue(faceInfo, "SuperscriptOffset", ascender);
                SetFieldValue(faceInfo, "SubscriptOffset", descender * 0.5f);
                SetFieldValue(faceInfo, "SubSize", 0.5f);
                SetFieldValue(faceInfo, "Underline", (metrics.underlineY != 0 ? metrics.underlineY : -0.1f) * pointSize);
                SetFieldValue(faceInfo, "UnderlineThickness", (metrics.underlineThickness != 0 ? metrics.underlineThickness : 0.05f) * pointSize);
                SetFieldValue(faceInfo, "TabWidth", pointSize * 4f); // 4 spaces typically
                SetFieldValue(faceInfo, "Padding", atlas.distanceRange);
                SetFieldValue(faceInfo, "AtlasWidth", (float)atlas.width);
                SetFieldValue(faceInfo, "AtlasHeight", (float)atlas.height);

                // Write faceInfo back
                if (fontInfoProp != null && fontInfoProp.CanWrite)
                    fontInfoProp.SetValue(fontAsset, faceInfo, null);
                else if (fontInfoField != null)
                    fontInfoField.SetValue(fontAsset, faceInfo);

                // Log the configured metrics for debugging
                TranslatorCore.LogInfo($"[CustomFontLoader] Configured FaceInfo: PointSize={pointSize}, Ascender={ascender:F2}, Descender={descender:F2}, LineHeight={metrics.lineHeight * pointSize:F2}");
                TranslatorCore.LogInfo($"[CustomFontLoader] Atlas dimensions: {atlas.width}x{atlas.height}, DistanceRange={atlas.distanceRange}");

                // DEBUG: Verify the values were actually written
                object verifyFaceInfo;
                if (fontInfoProp != null)
                    verifyFaceInfo = fontInfoProp.GetValue(fontAsset, null);
                else
                    verifyFaceInfo = fontInfoField.GetValue(fontAsset);
                if (verifyFaceInfo != null)
                {
                    var verifyType = verifyFaceInfo.GetType();
                    var atlasWField = verifyType.GetField("AtlasWidth", BindingFlags.Public | BindingFlags.Instance);
                    var atlasHField = verifyType.GetField("AtlasHeight", BindingFlags.Public | BindingFlags.Instance);
                    var pointSizeField = verifyType.GetField("PointSize", BindingFlags.Public | BindingFlags.Instance);

                    float? verifyW = atlasWField?.GetValue(verifyFaceInfo) as float?;
                    float? verifyH = atlasHField?.GetValue(verifyFaceInfo) as float?;
                    float? verifyPS = pointSizeField?.GetValue(verifyFaceInfo) as float?;

                    TranslatorCore.LogInfo($"[CustomFontLoader] VERIFY m_fontInfo: AtlasWidth={verifyW}, AtlasHeight={verifyH}, PointSize={verifyPS}");
                }
            }
            catch (Exception ex)
            {
                TranslatorCore.LogWarning($"[CustomFontLoader] Failed to setup face info: {ex.Message}");
            }
        }

        /// <summary>
        /// Sets up the glyph list. Tries modern TMP system (m_GlyphTable + m_CharacterTable) first,
        /// then falls back to legacy (m_glyphInfoList).
        /// </summary>
        private static void SetupGlyphs(object fontAsset, CustomFontInfo fontInfo, float pointSize)
        {
            var atlas = fontInfo.AtlasData.atlas;
            var glyphs = fontInfo.AtlasData.glyphs;
            bool yFlipped = atlas.yOrigin == "bottom";

            try
            {
                var fontAssetType = fontAsset.GetType();

                // Try MODERN system first (m_GlyphTable + m_CharacterTable)
                // This is what TMP actually uses in Unity 2019+
                object glyphTable = GetPropertyOrField(fontAsset, fontAssetType, "m_GlyphTable");
                object charTable = GetPropertyOrField(fontAsset, fontAssetType, "m_CharacterTable");

                if (glyphTable != null && charTable != null)
                {
                    TranslatorCore.LogInfo($"[CustomFontLoader] Using MODERN glyph system (m_GlyphTable + m_CharacterTable)");
                    SetupGlyphsModern(fontAsset, fontAssetType, glyphTable, charTable, fontInfo, pointSize, yFlipped);

                    // Mark lookup tables as dirty so TMP rebuilds them
                    SetPropertyOrField(fontAsset, fontAssetType, "IsFontAssetLookupTablesDirty", true);

                    // Clear lookup dictionaries to force rebuild
                    var glyphLookup = GetPropertyOrField(fontAsset, fontAssetType, "m_GlyphLookupDictionary");
                    if (glyphLookup != null)
                    {
                        var clearMethod = glyphLookup.GetType().GetMethod("Clear");
                        clearMethod?.Invoke(glyphLookup, null);
                    }
                    var charLookup = GetPropertyOrField(fontAsset, fontAssetType, "m_CharacterLookupDictionary");
                    if (charLookup != null)
                    {
                        var clearMethod = charLookup.GetType().GetMethod("Clear");
                        clearMethod?.Invoke(charLookup, null);
                    }

                    return;
                }

                // LEGACY fallback (m_glyphInfoList)
                TranslatorCore.LogInfo($"[CustomFontLoader] Using LEGACY glyph system (m_glyphInfoList)");
                SetupGlyphsLegacy(fontAsset, fontAssetType, fontInfo, pointSize, yFlipped);
            }
            catch (Exception ex)
            {
                TranslatorCore.LogWarning($"[CustomFontLoader] Failed to setup glyphs: {ex.Message}");
            }
        }

        /// <summary>
        /// Populate m_GlyphTable and m_CharacterTable (modern TMP system).
        /// </summary>
        private static void SetupGlyphsModern(object fontAsset, Type fontAssetType,
            object glyphTable, object charTable, CustomFontInfo fontInfo, float pointSize, bool yFlipped)
        {
            var atlas = fontInfo.AtlasData.atlas;
            var glyphs = fontInfo.AtlasData.glyphs;

            // Clear existing tables
            var clearGlyph = glyphTable.GetType().GetMethod("Clear");
            var clearChar = charTable.GetType().GetMethod("Clear");
            clearGlyph?.Invoke(glyphTable, null);
            clearChar?.Invoke(charTable, null);

            var addGlyph = glyphTable.GetType().GetMethod("Add");
            var addChar = charTable.GetType().GetMethod("Add");

            if (addGlyph == null || addChar == null)
            {
                TranslatorCore.LogWarning("[CustomFontLoader] Cannot find Add method on glyph/char tables");
                return;
            }

            // Get an existing glyph to discover its type (for creating new instances)
            // We already cleared, so we need to know the element type from the list's generic argument
            Type glyphType = GetListElementType(glyphTable);
            Type charType = GetListElementType(charTable);

            if (glyphType == null || charType == null)
            {
                TranslatorCore.LogWarning($"[CustomFontLoader] Cannot determine element types: glyph={glyphType?.Name}, char={charType?.Name}");
                return;
            }

            TranslatorCore.LogInfo($"[CustomFontLoader] Modern glyph type: {glyphType.FullName}, char type: {charType.FullName}");

            // Log properties of glyph type
            if (!_glyphFieldsLogged)
            {
                _glyphFieldsLogged = true;
                var props = glyphType.GetProperties(BindingFlags.Public | BindingFlags.Instance);
                TranslatorCore.LogInfo($"[CustomFontLoader] Modern Glyph props: {string.Join(", ", props.Select(p => p.Name + ":" + p.PropertyType.Name))}");
            }

            int addedCount = 0;
            foreach (var glyphInfo in glyphs)
            {
                try
                {
                    uint glyphIndex = (uint)addedCount;

                    // Create Glyph object
                    object newGlyph = CreateModernGlyph(glyphType, glyphIndex, glyphInfo, atlas, pointSize, yFlipped);
                    if (newGlyph == null) continue;

                    addGlyph.Invoke(glyphTable, new[] { newGlyph });

                    // Create TMP_Character mapping unicode -> glyph
                    object newChar = CreateModernCharacter(charType, (uint)glyphInfo.unicode, glyphIndex);
                    if (newChar != null)
                    {
                        addChar.Invoke(charTable, new[] { newChar });
                    }

                    addedCount++;
                }
                catch (Exception ex)
                {
                    if (addedCount < 3)
                        TranslatorCore.LogWarning($"[CustomFontLoader] Failed to create modern glyph U+{glyphInfo.unicode:X4}: {ex.Message}");
                }
            }

            TranslatorCore.LogInfo($"[CustomFontLoader] Added {addedCount} modern glyphs + characters");
        }

        /// <summary>
        /// Get the element type of a generic List (works with both System and IL2CPP lists).
        /// </summary>
        private static Type GetListElementType(object list)
        {
            if (list == null) return null;
            var listType = list.GetType();

            // Try generic argument
            if (listType.IsGenericType)
            {
                var args = listType.GetGenericArguments();
                if (args.Length > 0) return args[0];
            }

            // Try Item property return type
            var itemProp = listType.GetProperty("Item");
            if (itemProp != null) return itemProp.PropertyType;

            return null;
        }

        /// <summary>
        /// Create a modern UnityEngine.TextCore.Glyph object.
        /// </summary>
        private static object CreateModernGlyph(Type glyphType, uint index, GlyphInfo glyphInfo,
            AtlasInfo atlas, float pointSize, bool yFlipped)
        {
            try
            {
                // Try constructor with parameters first
                object glyph = null;

                // Try parameterless constructor
                try { glyph = Activator.CreateInstance(glyphType); } catch { }

                // If that fails, try ScriptableObject pattern (for IL2CPP types)
                if (glyph == null)
                {
                    glyph = TypeHelper.CreateScriptableObject(glyphType);
                }

                if (glyph == null)
                {
                    TranslatorCore.LogWarning($"[CustomFontLoader] Cannot create Glyph instance of type {glyphType.Name}");
                    return null;
                }

                var ab = glyphInfo.atlasBounds;
                var pb = glyphInfo.planeBounds;

                // Atlas coordinates
                float x = 0, y = 0, w = 0, h = 0;
                if (ab != null)
                {
                    x = ab.left;
                    y = yFlipped ? (atlas.height - ab.top) : ab.bottom;
                    w = ab.right - ab.left;
                    h = ab.top - ab.bottom;
                }

                // Metrics (in font units = em * pointSize)
                float metricsW = (pb != null) ? (pb.right - pb.left) * pointSize : 0;
                float metricsH = (pb != null) ? (pb.top - pb.bottom) * pointSize : 0;
                float bearingX = (pb?.left ?? 0) * pointSize;
                float bearingY = (pb?.top ?? 0) * pointSize;
                float advance = glyphInfo.advance * pointSize;

                // Set properties via reflection
                SetFieldValue(glyph, "m_Index", index);
                SetFieldValue(glyph, "index", index);
                SetFieldValue(glyph, "m_Scale", 1f);
                SetFieldValue(glyph, "scale", 1f);
                SetFieldValue(glyph, "m_AtlasIndex", 0);
                SetFieldValue(glyph, "atlasIndex", 0);

                // Set GlyphRect (x, y, width, height in atlas pixels)
                object glyphRect = GetPropertyOrField(glyph, glyph.GetType(), "m_GlyphRect");
                if (glyphRect == null)
                    glyphRect = GetPropertyOrField(glyph, glyph.GetType(), "glyphRect");

                if (glyphRect != null)
                {
                    SetFieldValue(glyphRect, "m_X", (int)x);
                    SetFieldValue(glyphRect, "m_Y", (int)y);
                    SetFieldValue(glyphRect, "m_Width", (int)w);
                    SetFieldValue(glyphRect, "m_Height", (int)h);
                    SetFieldValue(glyphRect, "x", (int)x);
                    SetFieldValue(glyphRect, "y", (int)y);
                    SetFieldValue(glyphRect, "width", (int)w);
                    SetFieldValue(glyphRect, "height", (int)h);
                }

                // Set GlyphMetrics (width, height, bearingX, bearingY, advance)
                object metrics = GetPropertyOrField(glyph, glyph.GetType(), "m_Metrics");
                if (metrics == null)
                    metrics = GetPropertyOrField(glyph, glyph.GetType(), "metrics");

                if (metrics != null)
                {
                    SetFieldValue(metrics, "m_Width", metricsW);
                    SetFieldValue(metrics, "m_Height", metricsH);
                    SetFieldValue(metrics, "m_HorizontalBearingX", bearingX);
                    SetFieldValue(metrics, "m_HorizontalBearingY", bearingY);
                    SetFieldValue(metrics, "m_HorizontalAdvance", advance);
                    SetFieldValue(metrics, "width", metricsW);
                    SetFieldValue(metrics, "height", metricsH);
                    SetFieldValue(metrics, "horizontalBearingX", bearingX);
                    SetFieldValue(metrics, "horizontalBearingY", bearingY);
                    SetFieldValue(metrics, "horizontalAdvance", advance);
                }

                // Log first few
                bool shouldLog = (glyphInfo.unicode >= 65 && glyphInfo.unicode <= 67)
                    || (glyphInfo.unicode >= 2309 && glyphInfo.unicode <= 2312);
                if (shouldLog)
                {
                    TranslatorCore.LogInfo($"[CustomFontLoader] Modern Glyph U+{glyphInfo.unicode:X4}: rect=({(int)x},{(int)y},{(int)w},{(int)h}), metrics=({metricsW:F1},{metricsH:F1},{bearingX:F1},{bearingY:F1},{advance:F1})");
                }

                return glyph;
            }
            catch (Exception ex)
            {
                TranslatorCore.LogWarning($"[CustomFontLoader] CreateModernGlyph error: {ex.Message}");
                return null;
            }
        }

        /// <summary>
        /// Create a modern TMP_Character object.
        /// </summary>
        private static object CreateModernCharacter(Type charType, uint unicode, uint glyphIndex)
        {
            try
            {
                object character = null;

                // Try constructor with (uint unicode, uint glyphIndex)
                var ctor2 = charType.GetConstructor(new Type[] { typeof(uint), typeof(uint) });
                if (ctor2 != null)
                {
                    character = ctor2.Invoke(new object[] { unicode, glyphIndex });
                }

                // Try parameterless constructor
                if (character == null)
                {
                    try { character = Activator.CreateInstance(charType); } catch { }
                }

                if (character == null) return null;

                // Set properties
                SetFieldValue(character, "m_Unicode", unicode);
                SetFieldValue(character, "unicode", unicode);
                SetFieldValue(character, "m_GlyphIndex", glyphIndex);
                SetFieldValue(character, "glyphIndex", glyphIndex);
                SetFieldValue(character, "m_Scale", 1f);
                SetFieldValue(character, "scale", 1f);

                return character;
            }
            catch
            {
                return null;
            }
        }

        /// <summary>
        /// Legacy glyph setup (m_glyphInfoList with TMP_Glyph objects).
        /// </summary>
        private static void SetupGlyphsLegacy(object fontAsset, Type fontAssetType,
            CustomFontInfo fontInfo, float pointSize, bool yFlipped)
        {
            var atlas = fontInfo.AtlasData.atlas;
            var glyphs = fontInfo.AtlasData.glyphs;

            var glyphListProp = fontAssetType.GetProperty("m_glyphInfoList", BindingFlags.Public | BindingFlags.Instance);
            var glyphListField = glyphListProp == null
                ? fontAssetType.GetField("m_glyphInfoList", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance)
                : null;

            if (glyphListProp == null && glyphListField == null)
            {
                TranslatorCore.LogWarning("[CustomFontLoader] m_glyphInfoList not found");
                return;
            }

            object existingList = glyphListProp != null
                ? glyphListProp.GetValue(fontAsset, null)
                : glyphListField?.GetValue(fontAsset);

            object glyphList;
            MethodInfo addMethod;

            if (existingList != null)
            {
                var clearMethod = existingList.GetType().GetMethod("Clear");
                clearMethod?.Invoke(existingList, null);
                glyphList = existingList;
                addMethod = existingList.GetType().GetMethod("Add");
            }
            else
            {
                var glyphListType = typeof(List<>).MakeGenericType(_tmpGlyphType ?? _tmpTextElementType ?? typeof(object));
                glyphList = Activator.CreateInstance(glyphListType);
                addMethod = glyphListType.GetMethod("Add");
            }

            foreach (var glyphInfo in glyphs)
            {
                var glyph = CreateGlyph(glyphInfo, atlas, pointSize, yFlipped);
                if (glyph != null)
                    addMethod.Invoke(glyphList, new[] { glyph });
            }

            if (glyphListProp != null && glyphListProp.CanWrite)
                glyphListProp.SetValue(fontAsset, glyphList, null);
            else if (glyphListField != null)
                glyphListField.SetValue(fontAsset, glyphList);

            BuildCharacterDictionary(fontAsset, glyphList);
            TranslatorCore.LogInfo($"[CustomFontLoader] Added {glyphs.Count} legacy glyphs");
        }

        private static bool _glyphFieldsLogged = false;

        /// <summary>
        /// Creates a single glyph object.
        /// </summary>
        private static object CreateGlyph(GlyphInfo glyphInfo, AtlasInfo atlas, float pointSize, bool yFlipped)
        {
            try
            {
                var glyphType = _tmpGlyphType ?? _tmpTextElementType;
                if (glyphType == null)
                    return null;

                // Log available fields AND properties once for debugging
                if (!_glyphFieldsLogged)
                {
                    _glyphFieldsLogged = true;
                    var fields = glyphType.GetFields(BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance);
                    var props = glyphType.GetProperties(BindingFlags.Public | BindingFlags.Instance);
                    TranslatorCore.LogInfo($"[CustomFontLoader] Glyph type: {glyphType.FullName}");
                    TranslatorCore.LogInfo($"[CustomFontLoader] Glyph fields ({fields.Length}): {string.Join(", ", fields.Select(f => f.Name + ":" + f.FieldType.Name))}");
                    TranslatorCore.LogInfo($"[CustomFontLoader] Glyph props ({props.Length}): {string.Join(", ", props.Select(p => p.Name + ":" + p.PropertyType.Name))}");
                }

                var glyph = Activator.CreateInstance(glyphType);

                var ab = glyphInfo.atlasBounds;
                var pb = glyphInfo.planeBounds;

                // Calculate atlas coordinates
                // For characters without visual bounds (like space), use zero dimensions
                float x = 0, y = 0, width = 0, height = 0;

                if (ab != null)
                {
                    // Shrink the region slightly to avoid sampling adjacent glyphs
                    float shrink = atlas.distanceRange * 0.82f;

                    x = ab.left + shrink;
                    // yFlipped (yOrigin="bottom") means we need to flip Y for TMP's coordinate system
                    y = yFlipped ? (atlas.height - ab.top + shrink) : (ab.top + shrink);
                    width = Math.Max(1, ab.right - ab.left - shrink * 2);
                    height = Math.Max(1, ab.top - ab.bottom - shrink * 2);
                }

                // Calculate offsets (planeBounds are in em units, multiply by pointSize)
                float xOffset = (pb?.left ?? 0) * pointSize;
                float yOffset = (pb?.top ?? 0) * pointSize;
                float xAdvance = glyphInfo.advance * pointSize;

                // Set glyph properties
                SetFieldValue(glyph, "id", glyphInfo.unicode);
                SetFieldValue(glyph, "x", x);
                SetFieldValue(glyph, "y", y);
                SetFieldValue(glyph, "width", width);
                SetFieldValue(glyph, "height", height);
                SetFieldValue(glyph, "xOffset", xOffset);
                SetFieldValue(glyph, "yOffset", yOffset);
                SetFieldValue(glyph, "xAdvance", xAdvance);
                SetFieldValue(glyph, "scale", 1f);

                // Log first few glyphs for debugging (Latin A-C and first Devanagari)
                bool shouldLog = (glyphInfo.unicode >= 65 && glyphInfo.unicode <= 67) // A, B, C
                    || (glyphInfo.unicode >= 2309 && glyphInfo.unicode <= 2315); // First Devanagari consonants
                if (shouldLog)
                {
                    TranslatorCore.LogInfo($"[CustomFontLoader] Glyph U+{glyphInfo.unicode:X4}: x={x}, y={y}, w={width}, h={height}, xOff={xOffset}, yOff={yOffset}, xAdv={xAdvance}");
                }

                return glyph;
            }
            catch (Exception ex)
            {
                TranslatorCore.LogWarning($"[CustomFontLoader] Failed to create glyph {glyphInfo.unicode}: {ex.Message}");
                return null;
            }
        }

        /// <summary>
        /// Builds the character dictionary for fast lookups.
        /// </summary>
        private static void BuildCharacterDictionary(object fontAsset, object glyphList)
        {
            try
            {
                var dictField = _tmpFontAssetType.GetField("m_characterDictionary", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance);
                if (dictField == null)
                    return;

                var glyphType = _tmpGlyphType ?? _tmpTextElementType;
                var dictType = typeof(Dictionary<,>).MakeGenericType(typeof(int), glyphType);
                var dict = Activator.CreateInstance(dictType);
                var dictAdd = dictType.GetMethod("Add");

                var listType = glyphList.GetType();
                var countProp = listType.GetProperty("Count");
                var indexer = listType.GetProperty("Item");

                int count = (int)countProp.GetValue(glyphList);
                for (int i = 0; i < count; i++)
                {
                    var glyph = indexer.GetValue(glyphList, new object[] { i });
                    var idField = glyphType.GetField("id", BindingFlags.Public | BindingFlags.Instance);
                    if (idField != null)
                    {
                        int id = (int)idField.GetValue(glyph);
                        try
                        {
                            dictAdd.Invoke(dict, new object[] { id, glyph });
                        }
                        catch { } // Ignore duplicates
                    }
                }

                dictField.SetValue(fontAsset, dict);

                // Log dictionary size for debugging
                var dictCount = dictType.GetProperty("Count");
                int dictSize = (int)dictCount.GetValue(dict);
                TranslatorCore.LogInfo($"[CustomFontLoader] Built character dictionary with {dictSize} entries");
            }
            catch (Exception ex)
            {
                TranslatorCore.LogWarning($"[CustomFontLoader] Failed to build character dictionary: {ex.Message}");
            }
        }

        /// <summary>
        /// Helper to set a field value via reflection.
        /// </summary>
        private static void SetFieldValue(object obj, string fieldName, object value)
        {
            if (obj == null) return;

            var type = obj.GetType();

            // Try property first (IL2CPP)
            var prop = type.GetProperty(fieldName, BindingFlags.Public | BindingFlags.Instance);
            if (prop != null && prop.CanWrite)
            {
                try
                {
                    if (value != null && prop.PropertyType != value.GetType())
                        value = Convert.ChangeType(value, prop.PropertyType);
                    prop.SetValue(obj, value, null);
                    return;
                }
                catch { }
            }

            // Try field (Mono)
            var field = type.GetField(fieldName, BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance);
            if (field != null)
            {
                try
                {
                    if (value != null && field.FieldType != value.GetType())
                        value = Convert.ChangeType(value, field.FieldType);
                    field.SetValue(obj, value);
                }
                catch { }
            }
        }

        // Cached LoadImage method
        private static MethodInfo _loadImageMethod;
        private static bool _loadImageMethodSearched;

        /// <summary>
        /// Loads image data into a Texture2D using reflection to call ImageConversion.LoadImage.
        /// This avoids compile-time dependency on ImageConversionModule.
        /// </summary>
        /// <summary>
        /// Encode a Texture2D to PNG via reflection (handles IL2CPP where EncodeToPNG may differ).
        /// </summary>
        /// <summary>
        /// SetPixels32 via reflection for IL2CPP compatibility.
        /// On IL2CPP, Color32[] may need conversion to Il2CppStructArray.
        /// </summary>
        private static bool SetPixels32Safe(Texture2D texture, Color32[] colors)
        {
            if (texture == null || colors == null) return false;

            // ALL access via reflection to avoid IL2CPP JIT crashes on stripped methods
            var texType = texture.GetType();
            foreach (var method in texType.GetMethods(BindingFlags.Public | BindingFlags.Instance))
            {
                if (method.Name != "SetPixels32") continue;
                var parameters = method.GetParameters();
                if (parameters.Length != 1) continue;

                var paramType = parameters[0].ParameterType;
                try
                {
                    // If it accepts Color32[], call directly
                    if (paramType == typeof(Color32[]))
                    {
                        method.Invoke(texture, new object[] { colors });
                        return true;
                    }

                    // IL2CPP: try to construct the expected array type from Color32[]
                    var ctor = paramType.GetConstructor(new Type[] { typeof(int) });
                    if (ctor != null)
                    {
                        var il2cppArray = ctor.Invoke(new object[] { colors.Length });
                        var indexer = paramType.GetProperty("Item");
                        if (indexer != null)
                        {
                            for (int i = 0; i < colors.Length; i++)
                                indexer.SetValue(il2cppArray, colors[i], new object[] { i });
                            method.Invoke(texture, new object[] { il2cppArray });
                            return true;
                        }
                    }
                }
                catch (Exception ex)
                {
                    TranslatorCore.LogWarning($"[CustomFontLoader] SetPixels32 reflection failed: {ex.Message}");
                }
            }

            // Last resort: set pixels one by one via SetPixel
            try
            {
                int w = texture.width;
                int h = texture.height;
                for (int i = 0; i < colors.Length && i < w * h; i++)
                {
                    int x = i % w;
                    int y = i / w;
                    texture.SetPixel(x, y, colors[i]);
                }
                return true;
            }
            catch (Exception ex)
            {
                TranslatorCore.LogWarning($"[CustomFontLoader] SetPixel fallback failed: {ex.Message}");
            }

            return false;
        }

        private static byte[] EncodeToPngSafe(Texture2D texture)
        {
            if (texture == null) return null;

            // Try ImageConversion.EncodeToPNG(texture) — newer Unity
            foreach (var asm in AppDomain.CurrentDomain.GetAssemblies())
            {
                var imageConvType = asm.GetType("UnityEngine.ImageConversion");
                if (imageConvType == null) continue;

                foreach (var method in imageConvType.GetMethods(BindingFlags.Public | BindingFlags.Static))
                {
                    if (method.Name != "EncodeToPNG") continue;
                    var parameters = method.GetParameters();
                    if (parameters.Length == 1)
                    {
                        try
                        {
                            var result = method.Invoke(null, new object[] { texture });
                            if (result is byte[] bytes) return bytes;

                            // IL2CPP: might return Il2CppStructArray<byte>
                            if (result != null)
                            {
                                var resultType = result.GetType();
                                var lengthProp = resultType.GetProperty("Length") ?? resultType.GetProperty("Count");
                                if (lengthProp != null)
                                {
                                    int length = (int)lengthProp.GetValue(result, null);
                                    var indexer = resultType.GetProperty("Item");
                                    if (indexer != null && length > 0)
                                    {
                                        byte[] data = new byte[length];
                                        for (int i = 0; i < length; i++)
                                            data[i] = (byte)indexer.GetValue(result, new object[] { i });
                                        return data;
                                    }
                                }
                            }
                        }
                        catch (Exception ex)
                        {
                            TranslatorCore.LogWarning($"[CustomFontLoader] EncodeToPNG failed: {ex.Message}");
                        }
                    }
                }
            }

            // Try Texture2D.EncodeToPNG() — older Unity (instance method)
            try
            {
                var method = texture.GetType().GetMethod("EncodeToPNG", BindingFlags.Public | BindingFlags.Instance);
                if (method != null)
                {
                    var result = method.Invoke(texture, null);
                    if (result is byte[] bytes) return bytes;
                }
            }
            catch { }

            return null;
        }

        private static bool LoadImageToTexture(Texture2D texture, byte[] data)
        {
            if (texture == null || data == null || data.Length == 0)
                return false;

            // Find the LoadImage method once
            if (!_loadImageMethodSearched)
            {
                _loadImageMethodSearched = true;
                FindLoadImageMethod();
            }

            if (_loadImageMethod == null)
                return false;

            try
            {
                // Convert byte[] to the expected parameter type if needed (IL2CPP)
                object dataArg = ConvertByteArrayForMethod(_loadImageMethod, data);

                object result;
                if (_loadImageMethod.IsStatic)
                {
                    result = _loadImageMethod.Invoke(null, new object[] { texture, dataArg });
                }
                else
                {
                    result = _loadImageMethod.Invoke(texture, new object[] { dataArg });
                }

                return result is bool b && b;
            }
            catch (Exception ex)
            {
                TranslatorCore.LogWarning($"[CustomFontLoader] LoadImage failed: {ex.Message}");
                return false;
            }
        }

        /// <summary>
        /// Find the LoadImage method, handling IL2CPP where parameter types differ.
        /// On IL2CPP, byte[] parameters become Il2CppStructArray&lt;byte&gt;.
        /// </summary>
        private static void FindLoadImageMethod()
        {
            // Strategy: search by name, accept any overload with 2 params (static) or 1 param (instance)
            // that has a byte-array-like second/first parameter

            // Try ImageConversion.LoadImage first (newer Unity)
            foreach (var asm in AppDomain.CurrentDomain.GetAssemblies())
            {
                var imageConvType = asm.GetType("UnityEngine.ImageConversion");
                if (imageConvType == null) continue;

                foreach (var method in imageConvType.GetMethods(BindingFlags.Public | BindingFlags.Static))
                {
                    if (method.Name != "LoadImage") continue;
                    var parameters = method.GetParameters();
                    // Looking for LoadImage(Texture2D, byte[]) — 2 params, second is byte-array-like
                    if (parameters.Length == 2 && IsTextureType(parameters[0].ParameterType) && IsByteArrayType(parameters[1].ParameterType))
                    {
                        _loadImageMethod = method;
                        TranslatorCore.LogInfo($"[CustomFontLoader] Found ImageConversion.LoadImage({parameters[0].ParameterType.Name}, {parameters[1].ParameterType.Name})");
                        return;
                    }
                }
            }

            // Try Texture2D.LoadImage(byte[]) (older Unity or instance method)
            var texType = typeof(Texture2D);
            // On IL2CPP, the actual runtime type may be different
            foreach (var method in texType.GetMethods(BindingFlags.Public | BindingFlags.Instance))
            {
                if (method.Name != "LoadImage") continue;
                var parameters = method.GetParameters();
                if (parameters.Length == 1 && IsByteArrayType(parameters[0].ParameterType))
                {
                    _loadImageMethod = method;
                    TranslatorCore.LogInfo($"[CustomFontLoader] Found Texture2D.LoadImage({parameters[0].ParameterType.Name})");
                    return;
                }
            }

            TranslatorCore.LogWarning("[CustomFontLoader] No LoadImage method found");
        }

        /// <summary>
        /// Check if a type is a Texture2D or IL2CPP equivalent.
        /// </summary>
        private static bool IsTextureType(Type type)
        {
            return typeof(Texture2D).IsAssignableFrom(type) || type.Name.Contains("Texture2D");
        }

        /// <summary>
        /// Check if a type is byte[] or an IL2CPP byte array equivalent.
        /// </summary>
        private static bool IsByteArrayType(Type type)
        {
            if (type == typeof(byte[])) return true;
            // IL2CPP: Il2CppStructArray<byte>, Il2CppInterop.Runtime.InteropTypes.Arrays.Il2CppStructArray`1[System.Byte]
            if (type.Name.Contains("Array") && type.FullName != null && type.FullName.Contains("Byte")) return true;
            return false;
        }

        /// <summary>
        /// Convert a byte[] to the type expected by the method parameter (handles IL2CPP array types).
        /// </summary>
        private static object ConvertByteArrayForMethod(MethodInfo method, byte[] data)
        {
            var parameters = method.GetParameters();
            // Find the byte-array parameter
            Type expectedType = null;
            foreach (var param in parameters)
            {
                if (IsByteArrayType(param.ParameterType))
                {
                    expectedType = param.ParameterType;
                    break;
                }
            }

            if (expectedType == null || expectedType == typeof(byte[]))
                return data; // Direct byte[] works

            // Need to convert to IL2CPP array type
            try
            {
                // Try constructor that accepts byte[]
                var ctor = expectedType.GetConstructor(new Type[] { typeof(byte[]) });
                if (ctor != null)
                {
                    return ctor.Invoke(new object[] { data });
                }

                // Try constructor(int) + indexer copy
                ctor = expectedType.GetConstructor(new Type[] { typeof(int) });
                if (ctor != null)
                {
                    var il2cppArray = ctor.Invoke(new object[] { data.Length });
                    var indexer = expectedType.GetProperty("Item");
                    if (indexer != null)
                    {
                        for (int i = 0; i < data.Length; i++)
                            indexer.SetValue(il2cppArray, data[i], new object[] { i });
                        return il2cppArray;
                    }
                }

                TranslatorCore.LogWarning($"[CustomFontLoader] Cannot convert byte[] to {expectedType.Name}");
            }
            catch (Exception ex)
            {
                TranslatorCore.LogWarning($"[CustomFontLoader] byte[] conversion failed: {ex.Message}");
            }

            return data; // Fallback, may fail
        }

        /// <summary>
        /// Converts an SDF texture for TMP compatibility.
        /// msdf-atlas-gen outputs SDF as grayscale in RGB channels, but TMP reads distance from Alpha channel.
        /// This method copies the R channel to Alpha to make the texture compatible with TMP shaders.
        /// </summary>
        private static void ConvertSdfTextureForTMP(Texture2D texture)
        {
            if (texture == null) return;

            try
            {
                // Use reflection-safe GetRawTextureData for IL2CPP compatibility
                // On IL2CPP, the method returns Il2CppStructArray<byte> instead of byte[]
                byte[] rawData = GetRawTextureDataSafe(texture);
                if (rawData == null || rawData.Length == 0)
                {
                    TranslatorCore.LogWarning("[CustomFontLoader] GetRawTextureData returned empty");
                    return;
                }

                // Determine bytes per pixel from format
                int bpp = GetBytesPerPixel(texture.format);
                if (bpp < 3)
                {
                    TranslatorCore.LogInfo($"[CustomFontLoader] Texture format {texture.format} (bpp={bpp}), skipping SDF conversion");
                    return;
                }

                int pixelCount = rawData.Length / bpp;
                bool needsConversion = false;

                // Determine channel offsets based on texture format
                // RGBA32: R=0, G=1, B=2, A=3
                // ARGB32: A=0, R=1, G=2, B=3
                // BGRA32: B=0, G=1, R=2, A=3
                int rOffset, gOffset, bOffset, alphaOffset;
                switch (texture.format)
                {
                    case TextureFormat.ARGB32:
                        alphaOffset = 0; rOffset = 1; gOffset = 2; bOffset = 3;
                        break;
                    case TextureFormat.BGRA32:
                        bOffset = 0; gOffset = 1; rOffset = 2; alphaOffset = 3;
                        break;
                    default: // RGBA32 and others
                        rOffset = 0; gOffset = 1; bOffset = 2; alphaOffset = bpp >= 4 ? 3 : -1;
                        break;
                }

                TranslatorCore.LogInfo($"[CustomFontLoader] Texture format: {texture.format}, offsets: R={rOffset} G={gOffset} B={bOffset} A={alphaOffset}");

                // Sample check: if alpha is mostly max but R varies, we need to copy R to A
                int sampleCount = Math.Min(100, pixelCount);
                int alphaOnes = 0;
                int rVariation = 0;
                int lastR = -1;

                for (int i = 0; i < sampleCount; i++)
                {
                    int idx = (i * (pixelCount / sampleCount)) * bpp;
                    if (idx + bpp > rawData.Length) break;

                    byte r = rawData[idx + rOffset];
                    byte a = alphaOffset >= 0 ? rawData[idx + alphaOffset] : (byte)255;

                    if (a > 252) alphaOnes++;
                    if (lastR >= 0 && Math.Abs(r - lastR) > 2) rVariation++;
                    lastR = r;
                }

                needsConversion = alphaOnes > sampleCount * 0.9f && rVariation > sampleCount * 0.1f;

                if (needsConversion && alphaOffset >= 0)
                {
                    TranslatorCore.LogInfo("[CustomFontLoader] Converting SDF texture: copying R channel to Alpha");
                    for (int i = 0; i < pixelCount; i++)
                    {
                        int idx = i * bpp;
                        if (idx + bpp > rawData.Length) break;
                        byte r = rawData[idx + rOffset];
                        rawData[idx + rOffset] = 255;  // R = white
                        rawData[idx + gOffset] = 255;   // G = white
                        rawData[idx + bOffset] = 255;   // B = white
                        rawData[idx + alphaOffset] = r;  // A = original R (SDF distance)
                    }
                    if (!LoadRawTextureDataSafe(texture, rawData))
                    {
                        TranslatorCore.LogWarning("[CustomFontLoader] Failed to write converted texture data back");
                        return;
                    }
                    texture.Apply();
                    TranslatorCore.LogInfo("[CustomFontLoader] SDF texture conversion complete");
                }
                else
                {
                    TranslatorCore.LogInfo("[CustomFontLoader] Texture appears to already have distance in Alpha channel");
                }
            }
            catch (Exception ex)
            {
                TranslatorCore.LogWarning($"[CustomFontLoader] Failed to convert SDF texture: {ex.Message}");
            }
        }

        /// <summary>
        /// Get raw texture data via reflection.
        /// On IL2CPP, GetRawTextureData() returns Il2CppStructArray&lt;byte&gt; instead of byte[].
        /// This method handles both cases.
        /// </summary>
        private static byte[] GetRawTextureDataSafe(Texture2D texture)
        {
            if (texture == null) return null;

            var type = texture.GetType();

            // Try all GetRawTextureData overloads via reflection
            foreach (var method in type.GetMethods(BindingFlags.Public | BindingFlags.Instance))
            {
                if (method.Name != "GetRawTextureData") continue;
                if (method.GetParameters().Length != 0) continue;
                if (method.IsGenericMethod) continue;

                try
                {
                    var result = method.Invoke(texture, null);
                    if (result == null) continue;

                    // Direct byte[] (Mono)
                    if (result is byte[] bytes)
                        return bytes;

                    // IL2CPP: result is Il2CppStructArray<byte> or similar
                    // It implements IEnumerable and has a Length property
                    var resultType = result.GetType();

                    // Try to get Length
                    var lengthProp = resultType.GetProperty("Length") ?? resultType.GetProperty("Count");
                    if (lengthProp == null) continue;

                    int length = (int)lengthProp.GetValue(result, null);
                    if (length == 0) continue;

                    // Try indexer access
                    var indexer = resultType.GetProperty("Item");
                    if (indexer != null)
                    {
                        byte[] data = new byte[length];
                        for (int i = 0; i < length; i++)
                        {
                            data[i] = (byte)indexer.GetValue(result, new object[] { i });
                        }
                        return data;
                    }

                    // Try as IList<byte> or IEnumerable
                    if (result is System.Collections.IEnumerable enumerable)
                    {
                        var list = new List<byte>();
                        foreach (var item in enumerable)
                        {
                            if (item is byte b)
                                list.Add(b);
                        }
                        if (list.Count > 0)
                            return list.ToArray();
                    }
                }
                catch (Exception ex)
                {
                    TranslatorCore.LogWarning($"[CustomFontLoader] GetRawTextureData reflection failed: {ex.Message}");
                }
            }

            return null;
        }

        /// <summary>
        /// Load raw texture data via reflection.
        /// On IL2CPP, LoadRawTextureData may expect Il2CppStructArray&lt;byte&gt; instead of byte[].
        /// </summary>
        private static bool LoadRawTextureDataSafe(Texture2D texture, byte[] data)
        {
            if (texture == null || data == null) return false;

            var type = texture.GetType();

            // Always use reflection to avoid MissingMethodException on IL2CPP
            // (direct call to LoadRawTextureData(byte[]) crashes on IL2CPP with unstripped methods)
            // Try via reflection, find a LoadRawTextureData that accepts our data
            foreach (var method in type.GetMethods(BindingFlags.Public | BindingFlags.Instance))
            {
                if (method.Name != "LoadRawTextureData") continue;
                var parameters = method.GetParameters();
                if (parameters.Length != 1) continue;

                var paramType = parameters[0].ParameterType;

                // If it accepts byte[], call directly
                if (paramType == typeof(byte[]))
                {
                    try
                    {
                        method.Invoke(texture, new object[] { data });
                        return true;
                    }
                    catch { continue; }
                }

                // If it accepts Il2CppStructArray<byte> or similar, try to construct one
                try
                {
                    // Try to create an instance of the expected type from byte[]
                    var ctor = paramType.GetConstructor(new Type[] { typeof(byte[]) });
                    if (ctor != null)
                    {
                        var il2cppArray = ctor.Invoke(new object[] { data });
                        method.Invoke(texture, new object[] { il2cppArray });
                        return true;
                    }

                    // Try with int length constructor + copy
                    ctor = paramType.GetConstructor(new Type[] { typeof(int) });
                    if (ctor != null)
                    {
                        var il2cppArray = ctor.Invoke(new object[] { data.Length });
                        var indexer = paramType.GetProperty("Item");
                        if (indexer != null)
                        {
                            for (int i = 0; i < data.Length; i++)
                                indexer.SetValue(il2cppArray, data[i], new object[] { i });
                            method.Invoke(texture, new object[] { il2cppArray });
                            return true;
                        }
                    }
                }
                catch (Exception ex)
                {
                    TranslatorCore.LogWarning($"[CustomFontLoader] LoadRawTextureData IL2CPP conversion failed: {ex.Message}");
                }
            }

            return false;
        }

        /// <summary>
        /// Get bytes per pixel for a texture format.
        /// </summary>
        private static int GetBytesPerPixel(TextureFormat format)
        {
            switch (format)
            {
                case TextureFormat.RGBA32:
                case TextureFormat.BGRA32:
                case TextureFormat.ARGB32:
                    return 4;
                case TextureFormat.RGB24:
                    return 3;
                case TextureFormat.Alpha8:
                case TextureFormat.R8:
                    return 1;
                case TextureFormat.RG16:
                case TextureFormat.R16:
                    return 2;
                case TextureFormat.RGBAFloat:
                    return 16;
                case TextureFormat.RGBAHalf:
                    return 8;
                default:
                    return 4; // Assume RGBA32 as default
            }
        }
    }
}
